{
  "name": "VietEng Genius - MOET Curriculum",
  "description": "An AI-powered English learning platform tailored for the Vietnam Ministry of Education curriculum (Grades 1-12), supporting major textbooks like Global Success, Friends Global, and Family and Friends."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GradeLevel {
  Grade1 = 'Grade 1',
  Grade2 = 'Grade 2',
  Grade3 = 'Grade 3',
  Grade4 = 'Grade 4',
  Grade5 = 'Grade 5',
  Grade6 = 'Grade 6',
  Grade7 = 'Grade 7',
  Grade8 = 'Grade 8',
  Grade9 = 'Grade 9',
  Grade10 = 'Grade 10',
  Grade11 = 'Grade 11',
  Grade12 = 'Grade 12',
}

export enum GameType {
  Quiz = 'Multiple Choice',
  Scramble = 'Sentence Scramble',
  Vocabulary = 'Word Match',
}

export interface QuestionData {
  id: number;
  questionText: string;
  options: string[];
  correctAnswer: string;
  explanation: string; // Explanation in Vietnamese
  topic: string; // The grammatical point or vocab topic
}

export interface GameSession {
  grade: GradeLevel;
  gameType: GameType;
  questions: QuestionData[];
  textbookContext: string;
}

export interface TextbookInfo {
  name: string;
  publisher: string;
}

import { GradeLevel, TextbookInfo } from './types';

// Map grades to likely textbooks based on MOET curriculum trends
export const TEXTBOOKS_BY_GRADE: Record<string, string[]> = {
  'Primary': [
    'Tiếng Anh 1/2/3/4/5 (Global Success)',
    'Family and Friends (National Edition)',
    'i-Learn Smart Start',
    'Explore Our World',
    'English Discovery',
    'Macmillan Next Move'
  ],
  'Secondary': [
    'Global Success (6-9)',
    'Friends Plus',
    'i-Learn Smart World',
    'Right On!',
    'English Discovery',
    'THiNK'
  ],
  'High': [
    'Global Success (10-12)',
    'Friends Global',
    'Bright',
    'i-Learn Smart World',
    'English Discovery'
  ]
};

export const GRADE_GROUPS = {
  'Primary School (Tiểu học)': [GradeLevel.Grade1, GradeLevel.Grade2, GradeLevel.Grade3, GradeLevel.Grade4, GradeLevel.Grade5],
  'Secondary School (THCS)': [GradeLevel.Grade6, GradeLevel.Grade7, GradeLevel.Grade8, GradeLevel.Grade9],
  'High School (THPT)': [GradeLevel.Grade10, GradeLevel.Grade11, GradeLevel.Grade12],
};

export const MOTIVATIONAL_MESSAGES = [
  "Giỏi lắm! (Great job!)",
  "Tiếp tục phát huy nhé! (Keep it up!)",
  "Bạn đang làm rất tốt! (You're doing great!)",
  "Tuyệt vời! (Awesome!)"
];

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { GameType, GradeLevel, QuestionData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    questions: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.INTEGER },
          questionText: { type: Type.STRING, description: "The question or sentence to work with." },
          options: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "4 possible answers. For scramble, this might be unused or contain distractors." 
          },
          correctAnswer: { type: Type.STRING, description: "The correct answer string." },
          explanation: { type: Type.STRING, description: "A short explanation in Vietnamese why the answer is correct." },
          topic: { type: Type.STRING, description: "The grammar or vocabulary topic (e.g., 'Present Simple', 'Animals')." }
        },
        required: ["id", "questionText", "options", "correctAnswer", "explanation", "topic"],
      },
    },
    textbookContext: { type: Type.STRING, description: "The specific textbook or unit this content was inspired by." }
  },
  required: ["questions", "textbookContext"],
};

export const generateGameContent = async (
  grade: GradeLevel,
  gameType: GameType,
  specificTextbook?: string
): Promise<{ questions: QuestionData[]; textbookContext: string }> => {

  const modelId = "gemini-2.5-flash"; // Fast and capable for this task

  let promptContext = "";

  if (gameType === GameType.Quiz) {
    promptContext = `Create 5 multiple-choice questions. 
    Focus on vocabulary, grammar points, and sentence structures found in the curriculum for ${grade}. 
    Ensure the difficulty matches the age group (Grade 1 is very simple words/images concepts, Grade 12 is advanced grammar/reading).`;
  } else if (gameType === GameType.Scramble) {
    promptContext = `Create 5 sentence scramble challenges. 
    'questionText' should be the scrambled words separated by slashes (e.g. 'is / name / My / Nam'). 
    'correctAnswer' should be the full correct sentence. 
    'options' can be random words related to the topic but are not strictly used for logic here, just fill them with 4 random words from the sentence.`;
  } else if (gameType === GameType.Vocabulary) {
    promptContext = `Create 5 vocabulary matching questions. 
    'questionText' should be an English word or a Vietnamese definition. 
    'correctAnswer' is the matching pair. 
    'options' should be 3 incorrect words/definitions and 1 correct one.`;
  }

  const textbookInstruction = specificTextbook 
    ? `Strictly base the content on the textbook series: "${specificTextbook}".` 
    : `Base the content on popular Vietnam MOET approved textbooks for this grade (e.g., Global Success, Friends Global, Family and Friends).`;

  const prompt = `
    You are an expert English teacher for the Vietnamese education system (Bộ Giáo Dục & Đào Tạo).
    Task: ${promptContext}
    Target Audience: Vietnamese students in ${grade}.
    Context: ${textbookInstruction}
    Output: JSON format containing an array of questions and the textbook context used.
    Ensure explanations are in Vietnamese to help the student learn.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.7, // Some creativity but adhering to facts
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text);
    return {
      questions: data.questions,
      textbookContext: data.textbookContext
    };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to generate game content. Please try again.");
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'danger';
  size?: 'sm' | 'md' | 'lg';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded-xl font-bold transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed transform active:scale-95";

  const variants = {
    primary: "bg-blue-600 hover:bg-blue-700 text-white shadow-lg shadow-blue-500/30 focus:ring-blue-500 border-b-4 border-blue-800 hover:border-blue-900 active:border-b-0 active:translate-y-1",
    secondary: "bg-purple-500 hover:bg-purple-600 text-white shadow-lg shadow-purple-500/30 focus:ring-purple-500 border-b-4 border-purple-700 hover:border-purple-800 active:border-b-0 active:translate-y-1",
    outline: "bg-white hover:bg-gray-50 text-gray-700 border-2 border-gray-200 hover:border-gray-300 focus:ring-gray-400",
    danger: "bg-red-500 hover:bg-red-600 text-white shadow-lg shadow-red-500/30 border-b-4 border-red-700 active:border-b-0 active:translate-y-1",
  };

  const sizes = {
    sm: "px-3 py-1.5 text-sm",
    md: "px-6 py-3 text-base",
    lg: "px-8 py-4 text-lg",
  };

  const widthClass = fullWidth ? "w-full" : "";

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${widthClass} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React from 'react';
import { Button } from './Button';
import { MOTIVATIONAL_MESSAGES } from '../constants';

interface ResultCardProps {
  score: number;
  total: number;
  onRetry: () => void;
  onHome: () => void;
}

export const ResultCard: React.FC<ResultCardProps> = ({ score, total, onRetry, onHome }) => {
  const percentage = Math.round((score / total) * 100);

  let message = "";
  if (percentage === 100) message = "Xuất sắc! (Perfect!) 🌟";
  else if (percentage >= 80) message = MOTIVATIONAL_MESSAGES[0];
  else if (percentage >= 60) message = MOTIVATIONAL_MESSAGES[1];
  else message = "Cố gắng hơn nữa nhé! (Try again!) 💪";

  return (
    <div className="bg-white rounded-3xl p-8 shadow-2xl max-w-md w-full mx-auto text-center border-4 border-yellow-400 animate-fade-in-up">
      <div className="mb-6">
        <div className="relative inline-block">
          <svg className="w-32 h-32 mx-auto text-yellow-400" viewBox="0 0 20 20" fill="currentColor">
            <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
          </svg>
        </div>
        <h2 className="text-3xl font-extrabold text-gray-800 mt-4">Kết Quả</h2>
        <p className="text-gray-500 text-lg">Results</p>
      </div>

      <div className="text-6xl font-black text-blue-600 mb-2">
        {score}/{total}
      </div>
      <p className="text-xl text-orange-500 font-bold mb-8">{message}</p>

      <div className="space-y-3">
        <Button onClick={onRetry} fullWidth variant="primary" size="lg">
          Chơi lại (Play Again)
        </Button>
        <Button onClick={onHome} fullWidth variant="outline" size="lg">
          Chọn cấp độ khác (Home)
        </Button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { QuestionData } from '../types';
import { Button } from './Button';

interface QuizGameProps {
  questions: QuestionData[];
  onComplete: (score: number) => void;
}

export const QuizGame: React.FC<QuizGameProps> = ({ questions, onComplete }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  const currentQuestion = questions[currentIndex];

  const handleOptionClick = (option: string) => {
    if (showFeedback) return;

    setSelectedOption(option);
    setShowFeedback(true);

    if (option === currentQuestion.correctAnswer) {
      setScore(prev => prev + 1);
    }
  };

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
      setSelectedOption(null);
      setShowFeedback(false);
    } else {
      onComplete(score + (selectedOption === currentQuestion.correctAnswer ? 0 : 0)); // Score already updated
    }
  };

  const getButtonVariant = (option: string) => {
    if (!showFeedback) return selectedOption === option ? 'primary' : 'outline';
    if (option === currentQuestion.correctAnswer) return 'primary'; // Greenish via logic below ideally, but simplified to primary
    if (option === selectedOption && option !== currentQuestion.correctAnswer) return 'danger';
    return 'outline';
  };

  const getButtonStyle = (option: string) => {
    if (!showFeedback) return "";
    if (option === currentQuestion.correctAnswer) return "!bg-green-500 !border-green-700 !text-white";
    return "";
  };

  return (
    <div className="max-w-2xl mx-auto w-full">
      {/* Progress Bar */}
      <div className="mb-6 bg-gray-200 rounded-full h-4 overflow-hidden">
        <div 
          className="bg-blue-500 h-full transition-all duration-500 ease-out"
          style={{ width: `${((currentIndex + 1) / questions.length) * 100}%` }}
        />
      </div>

      <div className="bg-white rounded-3xl shadow-xl p-6 md:p-8 border-b-8 border-gray-100">
        <div className="flex justify-between items-center mb-4">
          <span className="bg-blue-100 text-blue-800 text-xs font-bold px-3 py-1 rounded-full uppercase">
            Question {currentIndex + 1}/{questions.length}
          </span>
          <span className="text-gray-400 font-bold text-sm">{currentQuestion.topic}</span>
        </div>

        <h3 className="text-xl md:text-2xl font-bold text-gray-800 mb-8 leading-relaxed">
          {currentQuestion.questionText}
        </h3>

        <div className="grid grid-cols-1 gap-4 mb-6">
          {currentQuestion.options.map((option, idx) => (
            <Button
              key={idx}
              variant={getButtonVariant(option)}
              className={`text-left justify-start h-auto py-4 px-6 text-lg ${getButtonStyle(option)}`}
              onClick={() => handleOptionClick(option)}
              fullWidth
            >
              {option}
            </Button>
          ))}
        </div>

        {showFeedback && (
          <div className="bg-blue-50 border border-blue-100 rounded-xl p-4 mb-6 animate-fade-in">
            <p className="font-bold text-blue-800 mb-1">Giải thích (Explanation):</p>
            <p className="text-blue-700">{currentQuestion.explanation}</p>
          </div>
        )}

        <div className="flex justify-end">
          <Button 
            disabled={!showFeedback} 
            onClick={handleNext}
            size="lg"
            variant="secondary"
          >
            {currentIndex === questions.length - 1 ? 'Kết thúc (Finish)' : 'Câu tiếp theo (Next) →'}
          </Button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { GradeLevel, GameType, GameSession } from './types';
import { GRADE_GROUPS, TEXTBOOKS_BY_GRADE } from './constants';
import { generateGameContent } from './services/geminiService';
import { Button } from './components/Button';
import { QuizGame } from './components/QuizGame';
import { ResultCard } from './components/ResultCard';

// Helper icons
const Icons = {
  Book: () => <svg className="w-6 h-6 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>,
  Game: () => <svg className="w-6 h-6 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
};

const App: React.FC = () => {
  // State
  const [selectedGrade, setSelectedGrade] = useState<GradeLevel | null>(null);
  const [selectedGameType, setSelectedGameType] = useState<GameType | null>(null);
  const [selectedTextbook, setSelectedTextbook] = useState<string>('');
  const [gameData, setGameData] = useState<GameSession | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [finalScore, setFinalScore] = useState<number | null>(null);

  // Handlers
  const handleStartGame = async () => {
    if (!selectedGrade || !selectedGameType) return;

    setLoading(true);
    setError(null);
    try {
      // In a real app with Scramble/Vocab, we would pass different logic. 
      // For this demo, we use the generic "Questions" structure which supports Quiz well.
      // Scramble would need a slightly different UI component but similar data structure logic.
      const data = await generateGameContent(selectedGrade, selectedGameType, selectedTextbook);
      setGameData({
        grade: selectedGrade,
        gameType: selectedGameType,
        questions: data.questions,
        textbookContext: data.textbookContext
      });
    } catch (err) {
      setError("Có lỗi xảy ra khi tạo bài học. Vui lòng thử lại! (Error generating content)");
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setSelectedGrade(null);
    setSelectedGameType(null);
    setGameData(null);
    setFinalScore(null);
    setSelectedTextbook('');
    setError(null);
  };

  const handleRetry = () => {
    setFinalScore(null);
    // Reuse existing data
  };

  // Views
  const renderGradeSelection = () => (
    <div className="animate-fade-in space-y-8">
      <div className="text-center space-y-2">
        <h1 className="text-4xl md:text-5xl font-extrabold text-blue-900 tracking-tight">
          VietEng Genius 🇻🇳
        </h1>
        <p className="text-lg text-blue-600 font-medium">
          Học tiếng Anh theo chương trình chuẩn Bộ Giáo Dục
        </p>
      </div>

      {Object.entries(GRADE_GROUPS).map(([groupName, grades]) => (
        <div key={groupName} className="bg-white/80 backdrop-blur-sm rounded-3xl p-6 shadow-lg border border-blue-50">
          <h3 className="text-xl font-bold text-gray-700 mb-4 flex items-center">
            <span className="bg-blue-100 text-blue-600 p-2 rounded-lg mr-3">
              <Icons.Book />
            </span>
            {groupName}
          </h3>
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-3">
            {grades.map((grade) => (
              <Button 
                key={grade} 
                onClick={() => setSelectedGrade(grade)}
                variant="outline"
                className="hover:bg-blue-50 hover:border-blue-300"
              >
                {grade.replace('Grade ', 'Lớp ')}
              </Button>
            ))}
          </div>
        </div>
      ))}
    </div>
  );

  const renderConfiguration = () => {
    const availableTextbooks = selectedGrade 
      ? (parseInt(selectedGrade.split(' ')[1]) <= 5 ? TEXTBOOKS_BY_GRADE['Primary'] :
         parseInt(selectedGrade.split(' ')[1]) <= 9 ? TEXTBOOKS_BY_GRADE['Secondary'] : TEXTBOOKS_BY_GRADE['High'])
      : [];

    return (
      <div className="max-w-2xl mx-auto space-y-6 animate-fade-in">
        <Button onClick={() => setSelectedGrade(null)} variant="outline" size="sm">
          ← Quay lại (Back)
        </Button>

        <div className="text-center mb-8">
          <h2 className="text-3xl font-bold text-gray-800">Cấu hình bài học ({selectedGrade?.replace('Grade ', 'Lớp ')})</h2>
        </div>

        <div className="bg-white rounded-3xl p-6 shadow-xl border-t-4 border-blue-500">
          <label className="block text-gray-700 font-bold mb-3">Chọn giáo trình (Optional)</label>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mb-6">
            <div 
              onClick={() => setSelectedTextbook('')}
              className={`cursor-pointer p-4 rounded-xl border-2 transition-all ${selectedTextbook === '' ? 'border-blue-500 bg-blue-50' : 'border-gray-200 hover:border-blue-300'}`}
            >
              <div className="font-bold text-gray-800">Tổng hợp (General)</div>
              <div className="text-sm text-gray-500">Nội dung chung theo chuẩn Bộ GDĐT</div>
            </div>
            {availableTextbooks.map(tb => (
              <div 
                key={tb}
                onClick={() => setSelectedTextbook(tb)}
                className={`cursor-pointer p-4 rounded-xl border-2 transition-all ${selectedTextbook === tb ? 'border-blue-500 bg-blue-50' : 'border-gray-200 hover:border-blue-300'}`}
              >
                <div className="font-bold text-gray-800">{tb.split('(')[0]}</div>
                <div className="text-sm text-gray-500">{tb.includes('(') ? tb.split('(')[1].replace(')', '') : 'Phiên bản chuẩn'}</div>
              </div>
            ))}
          </div>

          <label className="block text-gray-700 font-bold mb-3">Chọn chế độ chơi (Game Mode)</label>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mb-8">
            <Button 
              variant={selectedGameType === GameType.Quiz ? 'primary' : 'outline'} 
              onClick={() => setSelectedGameType(GameType.Quiz)}
            >
              Trắc nghiệm
            </Button>
            <Button 
              variant={selectedGameType === GameType.Scramble ? 'primary' : 'outline'} 
              onClick={() => setSelectedGameType(GameType.Scramble)}
            >
              Sắp xếp câu
            </Button>
            <Button 
              variant={selectedGameType === GameType.Vocabulary ? 'primary' : 'outline'} 
              onClick={() => setSelectedGameType(GameType.Vocabulary)}
            >
              Từ vựng
            </Button>
          </div>

          <Button 
            onClick={handleStartGame} 
            fullWidth 
            size="lg" 
            variant="secondary"
            disabled={!selectedGameType}
          >
            Bắt đầu học ngay (Start)
          </Button>
        </div>
      </div>
    );
  };

  const renderLoading = () => (
    <div className="flex flex-col items-center justify-center min-h-[50vh] animate-pulse">
      <div className="w-24 h-24 border-8 border-blue-200 border-t-blue-600 rounded-full animate-spin mb-8"></div>
      <h3 className="text-2xl font-bold text-gray-700 mb-2">Đang tạo bài học...</h3>
      <p className="text-gray-500">AI đang chuẩn bị nội dung từ giáo trình {selectedTextbook || 'chuẩn'}</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 via-indigo-50 to-purple-50 p-4 md:p-8">
      <div className="max-w-6xl mx-auto">
        {/* Header (Simplified) */}
        {!gameData && !loading && (
           <header className="flex justify-end mb-4">
             {/* Could add user profile or settings here */}
           </header>
        )}

        {/* Error Banner */}
        {error && (
          <div className="bg-red-100 border-l-4 border-red-500 text-red-700 p-4 rounded-lg mb-6 max-w-2xl mx-auto shadow-sm">
             <p className="font-bold">Lỗi (Error)</p>
             <p>{error}</p>
             <button onClick={() => setError(null)} className="underline mt-2">Đóng</button>
          </div>
        )}

        {/* Content Router */}
        <main>
          {loading ? (
            renderLoading()
          ) : !selectedGrade ? (
            renderGradeSelection()
          ) : !gameData ? (
            renderConfiguration()
          ) : finalScore !== null ? (
            <div className="flex items-center justify-center min-h-[60vh]">
              <ResultCard 
                score={finalScore} 
                total={gameData.questions.length} 
                onRetry={handleRetry}
                onHome={handleReset}
              />
            </div>
          ) : (
            <div className="animate-fade-in">
               <div className="flex items-center justify-between mb-6 max-w-2xl mx-auto">
                 <Button onClick={handleReset} variant="outline" size="sm">Home</Button>
                 <span className="text-xs bg-white px-2 py-1 rounded border shadow-sm text-gray-500">
                    Source: {gameData.textbookContext}
                 </span>
               </div>
               {/* Currently mapping everything to QuizGame UI for MVP simplicity. 
                   Scramble/Vocab data structure fits, just might need UI tweak in v2. */}
               <QuizGame 
                 questions={gameData.questions} 
                 onComplete={setFinalScore} 
               />
            </div>
          )}
        </main>
      </div>

      <footer className="text-center text-gray-400 mt-12 text-sm">
        <p>© 2024 VietEng Genius. Powered by Gemini API.</p>
      </footer>
    </div>
  );
};

export default App;

export enum GradeLevel {
  Grade1 = 'Grade 1',
  Grade2 = 'Grade 2',
  Grade3 = 'Grade 3',
  Grade4 = 'Grade 4',
  Grade5 = 'Grade 5',
  Grade6 = 'Grade 6',
  Grade7 = 'Grade 7',
  Grade8 = 'Grade 8',
