import React, { useState, useEffect } from 'react';
import { QuestionData } from '../types';
import { Button } from './Button';

interface SpeakingGameProps {
  questions: QuestionData[];
  onComplete: (score: number) => void;
}

export const SpeakingGame: React.FC<SpeakingGameProps> = ({ questions, onComplete }) => {
  const [index, setIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState("");
  const [feedback, setFeedback] = useState<string | null>(null);

  const current = questions[index];

  // @ts-ignore - simple handling for webkitSpeechRecognition
  const Recognition = window.SpeechRecognition || window.webkitSpeechRecognition;

  const handleRecord = () => {
    if (!Recognition) {
      alert("Trình duyệt của bạn không hỗ trợ nhận diện giọng nói (hãy thử dùng Google Chrome).");
      return;
    }

    const recognition = new Recognition();
    recognition.lang = 'en-US';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    setIsListening(true);
    setTranscript("");
    setFeedback("Đang lắng nghe... (Listening...)");

    try {
      recognition.start();
    } catch (e) {
      console.error(e);
      setIsListening(false);
      setFeedback("Lỗi khởi động micro. Vui lòng tải lại trang.");
    }

    recognition.onresult = (event: any) => {
      const text = event.results[0][0].transcript;
      setTranscript(text);
      checkPronunciation(text);
      setIsListening(false);
    };

    recognition.onerror = (event: any) => {
      console.error("Speech Recognition Error:", event.error);
      setIsListening(false);

      switch (event.error) {
        case 'no-speech':
          setFeedback("Không nghe thấy tiếng. Bạn hãy nói to hơn nhé!");
          break;
        case 'not-allowed':
        case 'service-not-allowed':
          setFeedback("Vui lòng cấp quyền truy cập Micro trên trình duyệt!");
          break;
        case 'audio-capture':
          setFeedback("Không tìm thấy Micro. Vui lòng kiểm tra thiết bị.");
          break;
        case 'network':
          setFeedback("Lỗi kết nối mạng. Cần có internet để nhận diện giọng nói.");
          break;
        default:
          setFeedback(`Có lỗi xảy ra (${event.error}). Thử lại nhé!`);
      }
    };

    recognition.onend = () => {
      // Only reset listening state. Keep feedback if it's an error or result.
      // If it stopped without error or result (rare), provide timeout msg.
      setIsListening(false);
      setFeedback(prev => prev === "Đang lắng nghe... (Listening...)" ? "Hết thời gian. Thử lại nhé!" : prev);
    };
  };

  const checkPronunciation = (spoken: string) => {
    const target = current.speakingTarget || "";
    const normalize = (s: string) => s.toLowerCase().replace(/[.,!?]/g, '').trim();

    // Check for exact match or substring match for leniency
    if (normalize(spoken) === normalize(target) || normalize(target).includes(normalize(spoken))) {
      setFeedback("Tuyệt vời! Chính xác 100% 🎉");
      setScore(s => s + 1);
      setTimeout(nextQuestion, 2000);
    } else {
      setFeedback(`Gần đúng! Bạn nói: "${spoken}"`);
    }
  };

  const nextQuestion = () => {
    setFeedback(null);
    setTranscript("");
    if (index < questions.length - 1) setIndex(i => i + 1);
    else onComplete(score);
  };

  if (!Recognition) return <div className="text-center p-8">Trình duyệt không hỗ trợ Speaking.</div>;

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-3xl p-8 shadow-xl text-center">
      <span className="text-sm font-bold text-gray-400">Câu {index + 1}/{questions.length}</span>
      <h3 className="text-2xl font-bold text-gray-800 mt-2 mb-6">{current.questionText}</h3>

      <div className="bg-blue-50 p-6 rounded-2xl mb-8 border-2 border-blue-100">
        <p className="text-3xl font-extrabold text-blue-600 leading-tight">{current.speakingTarget}</p>
      </div>

      <div className="mb-8 min-h-[3rem]">
        {transcript && <p className="text-gray-500 italic mb-2">"{transcript}"</p>}
        {feedback && <p className={`font-bold animate-pulse ${feedback.includes('Tuyệt') ? 'text-green-600' : 'text-orange-500'}`}>{feedback}</p>}
      </div>

      <div className="flex gap-4 justify-center">
        <Button 
          onClick={handleRecord} 
          disabled={isListening}
          variant={isListening ? 'danger' : 'primary'}
          size="lg"
          className={`rounded-full w-24 h-24 flex items-center justify-center transition-all ${isListening ? 'ring-4 ring-red-200' : 'hover:scale-105'}`}
        >
          {isListening ? (
             <div className="flex flex-col items-center">
                <span className="animate-ping absolute inline-flex h-16 w-16 rounded-full bg-red-400 opacity-20"></span>
                <svg className="w-8 h-8 animate-pulse" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
                </svg>
             </div>
          ) : (
            <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          )}
        </Button>
      </div>
      <p className="text-xs text-gray-400 mt-4">Bấm vào micro và đọc to câu trên</p>

      <div className="mt-8 flex justify-center">
        <Button onClick={nextQuestion} variant="outline" size="sm">Bỏ qua (Skip)</Button>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { GameType, GradeLevel, QuestionData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    questions: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.INTEGER },
          questionText: { type: Type.STRING, description: "The visible question text." },
          options: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "Options for multiple choice. Empty for Speaking/Writing." 
          },
          correctAnswer: { type: Type.STRING, description: "Correct answer string." },
          explanation: { type: Type.STRING, description: "Vietnamese explanation." },
          topic: { type: Type.STRING },
          listeningScript: { type: Type.STRING, description: "Text for TTS to read. Use 'Speaker: Text' format for dialogues. Ensure proper punctuation (. ! ?)." },
          speakingTarget: { type: Type.STRING, description: "Sentence to read aloud (Speaking mode only)." },
        },
        required: ["id", "questionText", "explanation", "topic"],
      },
    },
    textbookContext: { type: Type.STRING }
  },
  required: ["questions", "textbookContext"],
};

export const generateGameContent = async (
  grade: GradeLevel,
  gameType: GameType,
  specificTextbook?: string
): Promise<{ questions: QuestionData[]; textbookContext: string }> => {

  const modelId = "gemini-2.5-flash"; 

  let specificInstruction = "";

  switch (gameType) {
    case GameType.Quiz:
    case GameType.FillBlank:
      specificInstruction = `Create 5 questions. For 'FillBlank', questionText should have a '_____' placeholder. Provide 4 options.`;
      break;
    case GameType.Listening:
      specificInstruction = `Create 3 listening challenges. 'listeningScript' MUST be a dialogue (e.g., 'Mom: Time for bed!\nTom: Not yet.') or a short story. Ensure distinct speakers and emotions. 'questionText' is a comprehension question.`;
      break;
    case GameType.Speaking:
      specificInstruction = `Create 5 speaking challenges. 'questionText' is instruction (e.g., 'Read this sentence'). 'speakingTarget' is the English sentence the student must say. Make it curriculum appropriate.`;
      break;
    case GameType.Writing:
      specificInstruction = `Create 1 writing challenge. 'questionText' is the essay/paragraph prompt (e.g., 'Write about your best friend'). 'topic' is the genre.`;
      break;
  }

  const prompt = `
    Role: Expert English Teacher for Vietnam MOET Curriculum.
    Grade: ${grade}.
    Task: ${specificInstruction}
    Textbook Reference: ${specificTextbook || "Standard MOET Curriculum (Global Success, Friends Global, etc.)"}.

    Curriculum Focus:
    - Grade 1-5: Family, Colors, Animals, School, Simple Pres/Cont Tense.
    - Grade 6-9: Environment, Community, Travel, Past/Future Tenses, Conditionals.
    - Grade 10-12: Society, Technology, Careers, IELTS foundation topics, Advanced Grammar.

    Output: JSON. Ensure explanations are in Vietnamese.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.7,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to generate content.");
  }
};

export const evaluateWriting = async (prompt: string, studentText: string, grade: string) => {
  const gradingSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      score: { type: Type.INTEGER, description: "Score out of 100" },
      feedback: { type: Type.STRING, description: "Constructive feedback in Vietnamese" },
      corrections: { type: Type.STRING, description: "Corrected version of the text" }
    }
  };

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: `Grade this English writing for a ${grade} Vietnamese student.
    Prompt: ${prompt}
    Student Answer: "${studentText}"
    Provide score (0-100), helpful feedback in Vietnamese, and a corrected version.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: gradingSchema
    }
  });

  return JSON.parse(response.text || "{}");
};

import React, { useState, useEffect, useRef } from 'react';
import { QuestionData } from '../types';
import { Button } from './Button';

interface ListeningGameProps {
  questions: QuestionData[];
  onComplete: (score: number) => void;
  isPrimary: boolean;
}

interface ScriptSegment {
  text: string;
  speaker: string;
  isExclamation: boolean;
  isQuestion: boolean;
}

export const ListeningGame: React.FC<ListeningGameProps> = ({ questions, onComplete, isPrimary }) => {
  const [index, setIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [feedback, setFeedback] = useState<string | null>(null);
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);

  const current = questions[index];
  const cancelRef = useRef<boolean>(false);

  useEffect(() => {
    const updateVoices = () => {
      const voices = window.speechSynthesis.getVoices();
      // Filter for English voices
      const enVoices = voices.filter(v => v.lang.startsWith('en'));
      setAvailableVoices(enVoices);
    };

    updateVoices();
    window.speechSynthesis.onvoiceschanged = updateVoices;

    return () => {
      window.speechSynthesis.cancel();
      window.speechSynthesis.onvoiceschanged = null;
    };
  }, []);

  // Parse text into meaningful chunks for TTS
  const parseScript = (text: string): ScriptSegment[] => {
    const segments: ScriptSegment[] = [];
    const lines = text.split(/\n+/);

    lines.forEach(line => {
      line = line.trim();
      if (!line) return;

      let speaker = 'Narrator';
      let content = line;

      // Try to parse "Speaker: Content"
      const colonIdx = line.indexOf(':');
      if (colonIdx > -1 && colonIdx < 20) {
        speaker = line.substring(0, colonIdx).trim();
        content = line.substring(colonIdx + 1).trim();
      }

      // Split sentences, keeping delimiters
      // Regex: Match text followed by delimiter, or text at end of string
      const sentenceRegex = /([^{.!?]+[.!?]+)|([^{.!?]+$)/g;
      const matches = content.match(sentenceRegex);

      if (matches) {
        matches.forEach(m => {
          const s = m.trim();
          if (s) {
            segments.push({
              text: s,
              speaker,
              isExclamation: s.includes('!'),
              isQuestion: s.includes('?')
            });
          }
        });
      }
    });

    return segments;
  };

  const playAudio = () => {
    if (!current.listeningScript) return;

    setIsPlaying(true);
    cancelRef.current = false;
    window.speechSynthesis.cancel();

    const segments = parseScript(current.listeningScript);

    // Assign voices to speakers
    const uniqueSpeakers = Array.from(new Set(segments.map(s => s.speaker)));
    const speakerConfig: Record<string, { voice: SpeechSynthesisVoice | null, pitch: number }> = {};

    uniqueSpeakers.forEach((spk, idx) => {
       // Alternate voices if available, or just modulate pitch
       // Preferred voices: Google US English, Microsoft Zira/David, etc.
       const voice = availableVoices[idx % availableVoices.length] || null;
       // Vary pitch slightly for different speakers: 0.9, 1.0, 1.1...
       const pitch = 1.0 + ((idx % 3) - 1) * 0.1; 
       speakerConfig[spk] = { voice, pitch };
    });

    let currentSegmentIdx = 0;

    const speakNext = () => {
      if (cancelRef.current || currentSegmentIdx >= segments.length) {
        setIsPlaying(false);
        return;
      }

      const seg = segments[currentSegmentIdx];
      const config = speakerConfig[seg.speaker];

      const u = new SpeechSynthesisUtterance(seg.text);
      u.lang = 'en-US';

      // Base Rate
      let rate = isPrimary ? 0.85 : 0.95;

      // Emotional adjustments
      let pitch = config.pitch;

      if (seg.isExclamation) {
        pitch += 0.15; // Higher pitch for excitement
        rate += 0.05;  // Slightly faster
        u.volume = 1.0;
      } else if (seg.isQuestion) {
        // Browser usually handles question intonation, but we can nudge pitch
        pitch += 0.05; 
      }

      if (config.voice) u.voice = config.voice;
      u.pitch = Math.max(0.5, Math.min(2, pitch));
      u.rate = rate;

      u.onend = () => {
        currentSegmentIdx++;
        // Pause duration logic
        let pause = 400; // Default sentence gap
        if (seg.isExclamation) pause = 600; // Dramatic pause

        // If next segment has a different speaker, add more pause
        if (currentSegmentIdx < segments.length) {
            if (segments[currentSegmentIdx].speaker !== seg.speaker) {
                pause = 800;
            }
        }

        setTimeout(speakNext, pause);
      };

      u.onerror = (e) => {
        console.error("TTS Error", e);
        setIsPlaying(false);
      };

      window.speechSynthesis.speak(u);
    };

    speakNext();
  };

  // Stop audio on unmount or retry
  useEffect(() => {
     return () => { cancelRef.current = true; window.speechSynthesis.cancel(); }
  }, [index]);

  const handleAnswer = (option: string) => {
    if (feedback) return;
    const isCorrect = option === current.correctAnswer;
    if (isCorrect) setScore(s => s + 1);
    setFeedback(isCorrect ? "Correct! 🎉" : `Incorrect. Answer: ${current.correctAnswer}`);

    setTimeout(() => {
      setFeedback(null);
      if (index < questions.length - 1) {
        setIndex(i => i + 1);
        setIsPlaying(false);
        window.speechSynthesis.cancel();
      } else {
        onComplete(score + (isCorrect ? 1 : 0));
      }
    }, 2500);
  };

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-3xl p-8 shadow-xl">
      <div className="text-center mb-8">
        <h3 className="text-xl font-bold text-gray-600 mb-4">Luyện Nghe (Question {index + 1}/{questions.length})</h3>

        <div className="flex flex-col items-center">
            <button 
            onClick={playAudio}
            disabled={isPlaying}
            className={`rounded-full p-6 transition-all transform active:scale-95 ${isPlaying ? 'bg-indigo-100 text-indigo-400 animate-pulse ring-4 ring-indigo-50' : 'bg-blue-100 hover:bg-blue-200 text-blue-600 shadow-lg hover:shadow-blue-200'}`}
            >
            <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
            </svg>
            </button>
            <p className="mt-3 text-sm font-bold text-gray-500 uppercase tracking-wide">
                {isPlaying ? "Đang đọc..." : "Bấm để nghe"}
            </p>
        </div>
      </div>

      <div className="bg-gray-50 rounded-2xl p-6 mb-6 border border-gray-100">
        <p className="text-xl font-medium text-gray-800 text-center leading-relaxed">{current.questionText}</p>
      </div>

      <div className="grid gap-4">
        {current.options?.map((opt, i) => (
          <Button 
            key={i} 
            onClick={() => handleAnswer(opt)} 
            variant="outline" 
            fullWidth 
            disabled={!!feedback}
            className="text-lg py-4 hover:border-blue-400 hover:bg-blue-50"
          >
            {opt}
          </Button>
        ))}
      </div>

      {feedback && (
        <div className={`mt-6 p-4 rounded-xl text-center font-bold text-lg animate-fade-in-up ${feedback.includes('Correct') ? 'bg-green-100 text-green-700 border border-green-200' : 'bg-red-100 text-red-700 border border-red-200'}`}>
          {feedback}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { QuestionData } from '../types';
import { Button } from './Button';

interface ListeningGameProps {
  questions: QuestionData[];
  onComplete: (score: number) => void;
  isPrimary: boolean;
}

interface ScriptSegment {
  text: string;
  speaker: string;
  isExclamation: boolean;
  isQuestion: boolean;
}

export const ListeningGame: React.FC<ListeningGameProps> = ({ questions, onComplete, isPrimary }) => {
  const [index, setIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [feedback, setFeedback] = useState<string | null>(null);
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);

  // Important: Keep reference to active utterance to prevent Garbage Collection (Chrome bug)
  const activeUtteranceRef = useRef<SpeechSynthesisUtterance | null>(null);
  const cancelRef = useRef<boolean>(false);

  const current = questions[index];

  useEffect(() => {
    const updateVoices = () => {
      const voices = window.speechSynthesis.getVoices();
      const enVoices = voices.filter(v => v.lang.startsWith('en'));
      setAvailableVoices(enVoices);
    };

    updateVoices();
    window.speechSynthesis.onvoiceschanged = updateVoices;

    return () => {
      cancelRef.current = true;
      window.speechSynthesis.cancel();
      window.speechSynthesis.onvoiceschanged = null;
    };
  }, []);

  // Stop audio when question changes
  useEffect(() => {
    cancelRef.current = true;
    window.speechSynthesis.cancel();
    setIsPlaying(false);
  }, [index]);

  const parseScript = (text: string): ScriptSegment[] => {
    const segments: ScriptSegment[] = [];
    if (!text) return segments;

    const lines = text.split(/\n+/);

    lines.forEach(line => {
      line = line.trim();
      if (!line) return;

      let speaker = 'Narrator';
      let content = line;

      // Try to parse "Speaker: Content"
      const colonIdx = line.indexOf(':');
      if (colonIdx > -1 && colonIdx < 20) {
        speaker = line.substring(0, colonIdx).trim();
        content = line.substring(colonIdx + 1).trim();
      }

      // Regex to split sentences but keep punctuation
      const sentenceRegex = /([^{.!?]+[.!?]+)|([^{.!?]+$)/g;
      const matches = content.match(sentenceRegex);

      if (matches) {
        matches.forEach(m => {
          const s = m.trim();
          if (s) {
            segments.push({
              text: s,
              speaker,
              isExclamation: s.includes('!'),
              isQuestion: s.includes('?')
            });
          }
        });
      }
    });

    return segments;
  };

  const playAudio = () => {
    if (!current.listeningScript) return;

    cancelRef.current = false;
    window.speechSynthesis.cancel();
    setIsPlaying(true);

    const segments = parseScript(current.listeningScript);

    if (segments.length === 0) {
        setIsPlaying(false);
        return;
    }

    const uniqueSpeakers = Array.from(new Set(segments.map(s => s.speaker)));
    const speakerConfig: Record<string, { voice: SpeechSynthesisVoice | null, pitch: number }> = {};

    uniqueSpeakers.forEach((spk, idx) => {
       const voice = availableVoices.length > 0 ? availableVoices[idx % availableVoices.length] : null;
       const pitch = 1.0 + ((idx % 3) - 1) * 0.1; 
       speakerConfig[spk] = { voice, pitch };
    });

    let currentSegmentIdx = 0;

    const speakNext = () => {
      if (cancelRef.current || currentSegmentIdx >= segments.length) {
        setIsPlaying(false);
        activeUtteranceRef.current = null;
        return;
      }

      const seg = segments[currentSegmentIdx];
      const config = speakerConfig[seg.speaker] || { voice: null, pitch: 1.0 };

      const u = new SpeechSynthesisUtterance(seg.text);
      activeUtteranceRef.current = u; // Prevent GC

      u.lang = 'en-US';

      let rate = isPrimary ? 0.85 : 0.95;
      let pitch = config.pitch;

      if (seg.isExclamation) {
        pitch += 0.15;
        rate += 0.05;
        u.volume = 1.0;
      } else if (seg.isQuestion) {
        pitch += 0.05; 
      }

      if (config.voice) u.voice = config.voice;
      u.pitch = Math.max(0.5, Math.min(2, pitch));
      u.rate = rate;

      u.onend = () => {
        currentSegmentIdx++;
        let pause = 400;
        if (seg.isExclamation) pause = 600;

        if (currentSegmentIdx < segments.length) {
            if (segments[currentSegmentIdx].speaker !== seg.speaker) {
                pause = 800;
            }
        }

        if (!cancelRef.current) {
             setTimeout(speakNext, pause);
        }
      };

      u.onerror = (e) => {
        console.warn("TTS Event Error:", e);
        // 'interrupted' or 'canceled' happens when we call cancel() manually, ignore those.
        if (e.error !== 'interrupted' && e.error !== 'canceled') {
           // Only stop UI if it's a real error
           setIsPlaying(false);
        }
      };

      window.speechSynthesis.speak(u);
    };

    speakNext();
  };

  const handleAnswer = (option: string) => {
    if (feedback) return;
    const isCorrect = option === current.correctAnswer;
    if (isCorrect) setScore(s => s + 1);
    setFeedback(isCorrect ? "Correct! 🎉" : `Incorrect. Answer: ${current.correctAnswer}`);

    setTimeout(() => {
      setFeedback(null);
      if (index < questions.length - 1) {
        setIndex(i => i + 1);
        // Cleanup happens in useEffect[index]
      } else {
        onComplete(score + (isCorrect ? 1 : 0));
      }
    }, 2500);
  };

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-3xl p-8 shadow-xl">
      <div className="text-center mb-8">
        <h3 className="text-xl font-bold text-gray-600 mb-4">Luyện Nghe (Question {index + 1}/{questions.length})</h3>

        <div className="flex flex-col items-center">
            <button 
            onClick={playAudio}
            disabled={isPlaying}
            className={`rounded-full p-6 transition-all transform active:scale-95 ${isPlaying ? 'bg-indigo-100 text-indigo-400 animate-pulse ring-4 ring-indigo-50' : 'bg-blue-100 hover:bg-blue-200 text-blue-600 shadow-lg hover:shadow-blue-200'}`}
            >
            <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
            </svg>
            </button>
            <p className="mt-3 text-sm font-bold text-gray-500 uppercase tracking-wide">
                {isPlaying ? "Đang đọc..." : "Bấm để nghe"}
            </p>
        </div>
      </div>

      <div className="bg-gray-50 rounded-2xl p-6 mb-6 border border-gray-100">
        <p className="text-xl font-medium text-gray-800 text-center leading-relaxed">{current.questionText}</p>
      </div>

      <div className="grid gap-4">
        {current.options?.map((opt, i) => (
          <Button 
            key={i} 
            onClick={() => handleAnswer(opt)} 
            variant="outline" 
            fullWidth 
            disabled={!!feedback}
            className="text-lg py-4 hover:border-blue-400 hover:bg-blue-50"
          >
            {opt}
          </Button>
        ))}
      </div>

      {feedback && (
        <div className={`mt-6 p-4 rounded-xl text-center font-bold text-lg animate-fade-in-up ${feedback.includes('Correct') ? 'bg-green-100 text-green-700 border border-green-200' : 'bg-red-100 text-red-700 border border-red-200'}`}>
          {feedback}
        </div>
      )}
    </div>
  );
};

