import { GoogleGenAI, Type, Schema } from "@google/genai";
import { GameType, GradeLevel, QuestionData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    questions: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.INTEGER },
          questionText: { type: Type.STRING, description: "The visible question text." },
          options: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "Options for multiple choice. Empty for Speaking/Writing." 
          },
          correctAnswer: { type: Type.STRING, description: "Correct answer string." },
          explanation: { type: Type.STRING, description: "Vietnamese explanation." },
          topic: { type: Type.STRING },
          listeningScript: { type: Type.STRING, description: "Text for TTS to read. Use 'Speaker: Text' format for dialogues. Ensure proper punctuation (. ! ?)." },
          speakingTarget: { type: Type.STRING, description: "Sentence to read aloud (Speaking mode only)." },
          imageDescription: { type: Type.STRING, description: "For Primary Grade Quiz only: A short English description of the image needed to answer the question (e.g., 'A red apple')." },
        },
        required: ["id", "questionText", "explanation", "topic"],
      },
    },
    textbookContext: { type: Type.STRING }
  },
  required: ["questions", "textbookContext"],
};

export const generateGameContent = async (
  grade: GradeLevel,
  gameType: GameType,
  specificTextbook?: string
): Promise<{ questions: QuestionData[]; textbookContext: string }> => {

  const modelId = "gemini-2.5-flash"; 
  const isPrimary = parseInt(grade.split(' ')[1]) <= 5;

  let specificInstruction = "";

  switch (gameType) {
    case GameType.Quiz:
    case GameType.FillBlank:
      specificInstruction = `Create 5 questions. For 'FillBlank', questionText should have a '_____' placeholder. Provide 4 options. ${isPrimary ? "For Grade 1-5, include an 'imageDescription' field for questions that need visual context (e.g. colors, animals, objects)." : ""}`;
      break;
    case GameType.Listening:
      specificInstruction = `Create 3 listening challenges. 'listeningScript' MUST be a dialogue (e.g., 'Mom: Time for bed!\nTom: Not yet.') or a short story. Ensure distinct speakers and emotions. 'questionText' is a comprehension question.`;
      break;
    case GameType.Speaking:
      specificInstruction = `Create 5 speaking challenges. 'questionText' is instruction (e.g., 'Read this sentence'). 'speakingTarget' is the English sentence the student must say. Make it curriculum appropriate.`;
      break;
    case GameType.Writing:
      specificInstruction = `Create 1 writing challenge. 'questionText' is the essay/paragraph prompt (e.g., 'Write about your best friend'). 'topic' is the genre.`;
      break;
  }

  const prompt = `
    Role: Expert English Teacher for Vietnam MOET Curriculum.
    Grade: ${grade}.
    Task: ${specificInstruction}
    Textbook Reference: ${specificTextbook || "Standard MOET Curriculum (Global Success, Friends Global, etc.)"}.

    Curriculum Focus:
    - Grade 1-5: Family, Colors, Animals, School, Simple Pres/Cont Tense. Focus on vocabulary with visual potential.
    - Grade 6-9: Environment, Community, Travel, Past/Future Tenses, Conditionals.
    - Grade 10-12: Society, Technology, Careers, IELTS foundation topics, Advanced Grammar.

    Output: JSON. Ensure explanations are in Vietnamese.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.7,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to generate content.");
  }
};

export const evaluateWriting = async (prompt: string, studentText: string, grade: string) => {
  const gradingSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      score: { type: Type.INTEGER, description: "Score out of 100" },
      feedback: { type: Type.STRING, description: "Constructive feedback in Vietnamese" },
      corrections: { type: Type.STRING, description: "Corrected version of the text" }
    }
  };

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: `Grade this English writing for a ${grade} Vietnamese student.
    Prompt: ${prompt}
    Student Answer: "${studentText}"
    Provide score (0-100), helpful feedback in Vietnamese, and a corrected version.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: gradingSchema
    }
  });

  return JSON.parse(response.text || "{}");
};

export const generateQuestionImage = async (description: string): Promise<string | null> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { text: `Draw a cute, simple, flat-style cartoon illustration for an educational quiz app for kids. White background. Subject: ${description}` },
        ],
      },
      // Note: No responseMimeType for image generation
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Image Gen Error:", error);
    return null;
  }
};

import React, { useState, useEffect } from 'react';
import { QuestionData } from '../types';
import { Button } from './Button';
import { generateQuestionImage } from '../services/geminiService';

interface QuizGameProps {
  questions: QuestionData[];
  onComplete: (score: number) => void;
  grade?: string;
}

export const QuizGame: React.FC<QuizGameProps> = ({ questions, onComplete, grade }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  // Image state
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [imageLoading, setImageLoading] = useState(false);

  const currentQuestion = questions[currentIndex];
  const isPrimary = grade ? parseInt(grade.split(' ')[1]) <= 5 : false;

  // Effect to load image if needed
  useEffect(() => {
    const loadImage = async () => {
      if (isPrimary && currentQuestion.imageDescription) {
        setImageLoading(true);
        setImageUrl(null);
        try {
          const url = await generateQuestionImage(currentQuestion.imageDescription);
          setImageUrl(url);
        } catch (e) {
          console.error(e);
        } finally {
          setImageLoading(false);
        }
      } else {
        setImageUrl(null);
      }
    };
    loadImage();
  }, [currentIndex, isPrimary, currentQuestion]);

  const handleOptionClick = (option: string) => {
    if (showFeedback) return;

    setSelectedOption(option);
    setShowFeedback(true);

    if (option === currentQuestion.correctAnswer) {
      setScore(prev => prev + 1);
    }
  };

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
      setSelectedOption(null);
      setShowFeedback(false);
    } else {
      onComplete(score + (selectedOption === currentQuestion.correctAnswer ? 0 : 0));
    }
  };

  const getButtonVariant = (option: string) => {
    if (!showFeedback) return selectedOption === option ? 'primary' : 'outline';
    if (option === currentQuestion.correctAnswer) return 'primary'; 
    if (option === selectedOption && option !== currentQuestion.correctAnswer) return 'danger';
    return 'outline';
  };

  const getButtonStyle = (option: string) => {
    if (!showFeedback) return "";
    if (option === currentQuestion.correctAnswer) return "!bg-green-500 !border-green-700 !text-white";
    return "";
  };

  return (
    <div className="max-w-2xl mx-auto w-full">
      {/* Progress Bar */}
      <div className="mb-6 bg-gray-200 rounded-full h-4 overflow-hidden">
        <div 
          className="bg-blue-500 h-full transition-all duration-500 ease-out"
          style={{ width: `${((currentIndex + 1) / questions.length) * 100}%` }}
        />
      </div>

      <div className="bg-white rounded-3xl shadow-xl p-6 md:p-8 border-b-8 border-gray-100">
        <div className="flex justify-between items-center mb-4">
          <span className="bg-blue-100 text-blue-800 text-xs font-bold px-3 py-1 rounded-full uppercase">
            Question {currentIndex + 1}/{questions.length}
          </span>
          <span className="text-gray-400 font-bold text-sm">{currentQuestion.topic}</span>
        </div>

        {/* Image Section for Primary */}
        {(isPrimary && (currentQuestion.imageDescription || imageLoading)) && (
          <div className="mb-6 flex justify-center">
            {imageLoading ? (
              <div className="w-64 h-64 bg-gray-100 rounded-2xl animate-pulse flex items-center justify-center border-2 border-dashed border-gray-300">
                <div className="text-center">
                  <svg className="w-10 h-10 text-gray-300 animate-spin mx-auto mb-2" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  <span className="text-gray-400 text-xs font-bold">AI đang vẽ...</span>
                </div>
              </div>
            ) : imageUrl ? (
              <img 
                src={imageUrl} 
                alt="Quiz visual" 
                className="w-64 h-64 object-contain rounded-2xl border-4 border-white shadow-lg bg-white" 
              />
            ) : null}
          </div>
        )}

        <h3 className="text-xl md:text-2xl font-bold text-gray-800 mb-8 leading-relaxed text-center">
          {currentQuestion.questionText}
        </h3>

        <div className="grid grid-cols-1 gap-4 mb-6">
          {currentQuestion.options?.map((option, idx) => (
            <Button
              key={idx}
              variant={getButtonVariant(option)}
              className={`text-left justify-start h-auto py-4 px-6 text-lg ${getButtonStyle(option)}`}
              onClick={() => handleOptionClick(option)}
              fullWidth
            >
              {option}
            </Button>
          ))}
        </div>

        {showFeedback && (
          <div className="bg-blue-50 border border-blue-100 rounded-xl p-4 mb-6 animate-fade-in">
            <p className="font-bold text-blue-800 mb-1">Giải thích (Explanation):</p>
            <p className="text-blue-700">{currentQuestion.explanation}</p>
          </div>
        )}

        <div className="flex justify-end">
          <Button 
            disabled={!showFeedback} 
            onClick={handleNext}
            size="lg"
            variant="secondary"
          >
            {currentIndex === questions.length - 1 ? 'Kết thúc (Finish)' : 'Câu tiếp theo (Next) →'}
          </Button>
        </div>
      </div>
    </div>
  );
};

