import React, { useState, useEffect, useRef } from 'react';
import { QuestionData } from '../types';
import { Button } from './Button';

interface ListeningGameProps {
  questions: QuestionData[];
  onComplete: (score: number) => void;
}

interface ScriptSegment {
  text: string;
  speaker: string;
  isExclamation: boolean;
  isQuestion: boolean;
}

export const ListeningGame: React.FC<ListeningGameProps> = ({ questions, onComplete }) => {
  const [index, setIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [feedback, setFeedback] = useState<string | null>(null);
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);

  // Important: Keep reference to active utterance to prevent Garbage Collection (Chrome bug)
  const activeUtteranceRef = useRef<SpeechSynthesisUtterance | null>(null);
  const cancelRef = useRef<boolean>(false);

  const current = questions[index];

  useEffect(() => {
    const updateVoices = () => {
      const voices = window.speechSynthesis.getVoices();
      const enVoices = voices.filter(v => v.lang.startsWith('en'));
      setAvailableVoices(enVoices);
    };

    updateVoices();
    window.speechSynthesis.onvoiceschanged = updateVoices;

    return () => {
      cancelRef.current = true;
      window.speechSynthesis.cancel();
      window.speechSynthesis.onvoiceschanged = null;
    };
  }, []);

  // Stop audio when question changes
  useEffect(() => {
    cancelRef.current = true;
    window.speechSynthesis.cancel();
    setIsPlaying(false);
  }, [index]);

  const parseScript = (text: string): ScriptSegment[] => {
    const segments: ScriptSegment[] = [];
    if (!text) return segments;

    const lines = text.split(/\n+/);

    lines.forEach(line => {
      line = line.trim();
      if (!line) return;

      let speaker = 'Narrator';
      let content = line;

      // Try to parse "Speaker: Content"
      const colonIdx = line.indexOf(':');
      if (colonIdx > -1 && colonIdx < 20) {
        speaker = line.substring(0, colonIdx).trim();
        content = line.substring(colonIdx + 1).trim();
      }

      // Regex to split sentences but keep punctuation
      const sentenceRegex = /([^{.!?]+[.!?]+)|([^{.!?]+$)/g;
      const matches = content.match(sentenceRegex);

      if (matches) {
        matches.forEach(m => {
          const s = m.trim();
          if (s) {
            segments.push({
              text: s,
              speaker,
              isExclamation: s.includes('!'),
              isQuestion: s.includes('?')
            });
          }
        });
      }
    });

    return segments;
  };

  const playAudio = () => {
    if (!current.listeningScript) return;

    cancelRef.current = false;
    window.speechSynthesis.cancel();
    setIsPlaying(true);

    const segments = parseScript(current.listeningScript);

    if (segments.length === 0) {
        setIsPlaying(false);
        return;
    }

    const uniqueSpeakers = Array.from(new Set(segments.map(s => s.speaker)));
    const speakerConfig: Record<string, { voice: SpeechSynthesisVoice | null, pitch: number }> = {};

    uniqueSpeakers.forEach((spk, idx) => {
       const voice = availableVoices.length > 0 ? availableVoices[idx % availableVoices.length] : null;
       const pitch = 1.0 + ((idx % 3) - 1) * 0.1; 
       speakerConfig[spk] = { voice, pitch };
    });

    let currentSegmentIdx = 0;

    const speakNext = () => {
      if (cancelRef.current || currentSegmentIdx >= segments.length) {
        setIsPlaying(false);
        activeUtteranceRef.current = null;
        return;
      }

      const seg = segments[currentSegmentIdx];
      const config = speakerConfig[seg.speaker] || { voice: null, pitch: 1.0 };

      const u = new SpeechSynthesisUtterance(seg.text);
      activeUtteranceRef.current = u; // Prevent GC

      u.lang = 'en-US';

      let rate = 0.95; // Standard speed for Secondary/High school
      let pitch = config.pitch;

      if (seg.isExclamation) {
        pitch += 0.15;
        rate += 0.05;
        u.volume = 1.0;
      } else if (seg.isQuestion) {
        pitch += 0.05; 
      }

      if (config.voice) u.voice = config.voice;
      u.pitch = Math.max(0.5, Math.min(2, pitch));
      u.rate = rate;

      u.onend = () => {
        currentSegmentIdx++;
        let pause = 400;
        if (seg.isExclamation) pause = 600;

        if (currentSegmentIdx < segments.length) {
            if (segments[currentSegmentIdx].speaker !== seg.speaker) {
                pause = 800;
            }
        }

        if (!cancelRef.current) {
             setTimeout(speakNext, pause);
        }
      };

      u.onerror = (e) => {
        console.warn("TTS Event Error:", e);
        // 'interrupted' or 'canceled' happens when we call cancel() manually, ignore those.
        if (e.error !== 'interrupted' && e.error !== 'canceled') {
           // Only stop UI if it's a real error
           setIsPlaying(false);
        }
      };

      window.speechSynthesis.speak(u);
    };

    speakNext();
  };

  const handleAnswer = (option: string) => {
    if (feedback) return;
    const isCorrect = option === current.correctAnswer;
    if (isCorrect) setScore(s => s + 1);
    setFeedback(isCorrect ? "Correct! 🎉" : `Incorrect. Answer: ${current.correctAnswer}`);

    setTimeout(() => {
      setFeedback(null);
      if (index < questions.length - 1) {
        setIndex(i => i + 1);
        // Cleanup happens in useEffect[index]
      } else {
        onComplete(score + (isCorrect ? 1 : 0));
      }
    }, 2500);
  };

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-3xl p-8 shadow-xl">
      <div className="text-center mb-8">
        <h3 className="text-xl font-bold text-gray-600 mb-4">Luyện Nghe (Question {index + 1}/{questions.length})</h3>

        <div className="flex flex-col items-center">
            <button 
            onClick={playAudio}
            disabled={isPlaying}
            className={`rounded-full p-6 transition-all transform active:scale-95 ${isPlaying ? 'bg-indigo-100 text-indigo-400 animate-pulse ring-4 ring-indigo-50' : 'bg-blue-100 hover:bg-blue-200 text-blue-600 shadow-lg hover:shadow-blue-200'}`}
            >
            <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
            </svg>
            </button>
            <p className="mt-3 text-sm font-bold text-gray-500 uppercase tracking-wide">
                {isPlaying ? "Đang đọc..." : "Bấm để nghe"}
            </p>
        </div>
      </div>

      <div className="bg-gray-50 rounded-2xl p-6 mb-6 border border-gray-100">
        <p className="text-xl font-medium text-gray-800 text-center leading-relaxed">{current.questionText}</p>
      </div>

      <div className="grid gap-4">
        {current.options?.map((opt, i) => (
          <Button 
            key={i} 
            onClick={() => handleAnswer(opt)} 
            variant="outline" 
            fullWidth 
            disabled={!!feedback}
            className="text-lg py-4 hover:border-blue-400 hover:bg-blue-50"
          >
            {opt}
          </Button>
        ))}
      </div>

      {feedback && (
        <div className={`mt-6 p-4 rounded-xl text-center font-bold text-lg animate-fade-in-up ${feedback.includes('Correct') ? 'bg-green-100 text-green-700 border border-green-200' : 'bg-red-100 text-red-700 border border-red-200'}`}>
          {feedback}
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { QuestionData } from '../types';
import { Button } from './Button';

interface QuizGameProps {
  questions: QuestionData[];
  onComplete: (score: number) => void;
}

export const QuizGame: React.FC<QuizGameProps> = ({ questions, onComplete }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  const currentQuestion = questions[currentIndex];

  const handleOptionClick = (option: string) => {
    if (showFeedback) return;

    setSelectedOption(option);
    setShowFeedback(true);

    if (option === currentQuestion.correctAnswer) {
      setScore(prev => prev + 1);
    }
  };

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
      setSelectedOption(null);
      setShowFeedback(false);
    } else {
      onComplete(score + (selectedOption === currentQuestion.correctAnswer ? 0 : 0));
    }
  };

  const getButtonVariant = (option: string) => {
    if (!showFeedback) return selectedOption === option ? 'primary' : 'outline';
    if (option === currentQuestion.correctAnswer) return 'primary'; 
    if (option === selectedOption && option !== currentQuestion.correctAnswer) return 'danger';
    return 'outline';
  };

  const getButtonStyle = (option: string) => {
    if (!showFeedback) return "";
    if (option === currentQuestion.correctAnswer) return "!bg-green-500 !border-green-700 !text-white";
    return "";
  };

  return (
    <div className="max-w-2xl mx-auto w-full">
      {/* Progress Bar */}
      <div className="mb-6 bg-gray-200 rounded-full h-4 overflow-hidden">
        <div 
          className="bg-blue-500 h-full transition-all duration-500 ease-out"
          style={{ width: `${((currentIndex + 1) / questions.length) * 100}%` }}
        />
      </div>

      <div className="bg-white rounded-3xl shadow-xl p-6 md:p-8 border-b-8 border-gray-100">
        <div className="flex justify-between items-center mb-4">
          <span className="bg-blue-100 text-blue-800 text-xs font-bold px-3 py-1 rounded-full uppercase">
            Question {currentIndex + 1}/{questions.length}
          </span>
          <span className="text-gray-400 font-bold text-sm">{currentQuestion.topic}</span>
        </div>

        <h3 className="text-xl md:text-2xl font-bold text-gray-800 mb-8 leading-relaxed text-center">
          {currentQuestion.questionText}
        </h3>

        <div className="grid grid-cols-1 gap-4 mb-6">
          {currentQuestion.options?.map((option, idx) => (
            <Button
              key={idx}
              variant={getButtonVariant(option)}
              className={`text-left justify-start h-auto py-4 px-6 text-lg ${getButtonStyle(option)}`}
              onClick={() => handleOptionClick(option)}
              fullWidth
            >
              {option}
            </Button>
          ))}
        </div>

        {showFeedback && (
          <div className="bg-blue-50 border border-blue-100 rounded-xl p-4 mb-6 animate-fade-in">
            <p className="font-bold text-blue-800 mb-1">Giải thích (Explanation):</p>
            <p className="text-blue-700">{currentQuestion.explanation}</p>
          </div>
        )}

        <div className="flex justify-end">
          <Button 
            disabled={!showFeedback} 
            onClick={handleNext}
            size="lg"
            variant="secondary"
          >
            {currentIndex === questions.length - 1 ? 'Kết thúc (Finish)' : 'Câu tiếp theo (Next) →'}
          </Button>
        </div>
      </div>
    </div>
  );
};

