const App: React.FC = () => {
  // State
  const [selectedGrade, setSelectedGrade] = useState<GradeLevel | null>(null);
  const [selectedGameType, setSelectedGameType] = useState<GameType | null>(null);
  const [selectedSubSkill, setSelectedSubSkill] = useState<GrammarSubSkill | null>(null);
  const [selectedTextbook, setSelectedTextbook] = useState<string>('');
  const [gameData, setGameData] = useState<GameSession | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [finalScore, setFinalScore] = useState<number | null>(null);
  const [totalPoints, setTotalPoints] = useState(0);
  const [showBadges, setShowBadges] = useState(false);

  // Calculate current rank info
  const currentBadge = BADGE_LEVELS.slice().reverse().find(b => totalPoints >= b.score);
  const nextBadge = BADGE_LEVELS.find(b => totalPoints < b.score);

  // Load points
  useEffect(() => {
    const pts = localStorage.getItem('vieteng_points');
    if (pts) setTotalPoints(parseInt(pts));
  }, [finalScore, showBadges]); // Refresh when score updates or badge modal opens

  // Handlers
  const handleStartGame = async () => {
    if (!selectedGrade || !selectedGameType) return;
    if (selectedGameType === GameType.Grammar && !selectedSubSkill) return;

    setLoading(true);
    setError(null);
    try {
      const data = await generateGameContent(selectedGrade, selectedGameType, selectedTextbook, selectedSubSkill || undefined);

      if (!data || !data.questions || data.questions.length === 0) {
        throw new Error("Không tìm thấy câu hỏi nào. Vui lòng thử lại.");
      }

      setGameData({
        grade: selectedGrade,
        gameType: selectedGameType,
        subSkill: selectedSubSkill || undefined,
        questions: data.questions,
        textbookContext: data.textbookContext
      });
    } catch (err) {
      setError("Có lỗi xảy ra khi tạo bài học. Vui lòng thử lại! (Error generating content)");
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setSelectedGrade(null);
    setSelectedGameType(null);
    setSelectedSubSkill(null);
    setGameData(null);
    setFinalScore(null);
    setSelectedTextbook('');
    setError(null);
  };

  const renderGameComponent = () => {
    if (!gameData) return null;

    const commonProps = {
      questions: gameData.questions,
      onComplete: setFinalScore
    };

    switch (gameData.gameType) {
      case GameType.Listening:
        return <ListeningGame {...commonProps} />;
      case GameType.Speaking:
        return <SpeakingGame {...commonProps} />;
      case GameType.Writing:
        return <WritingGame {...commonProps} grade={gameData.grade} />;
      case GameType.Grammar:
        // Pass subSkill here
        return <QuizGame {...commonProps} subSkill={gameData.subSkill} />;
      default:
        return <QuizGame {...commonProps} />;
    }
  };

  // Badge Modal
  const renderBadgeModal = () => (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm animate-fade-in">
      <div className="bg-white/95 backdrop-blur-xl rounded-3xl p-6 md:p-8 max-w-2xl w-full shadow-2xl relative max-h-[90vh] overflow-y-auto border border-white/50">
        <button 
          onClick={() => setShowBadges(false)}
          className="absolute top-4 right-4 p-2 bg-gray-100/50 rounded-full hover:bg-gray-200 transition-colors"
        >
          <Icons.Close />
        </button>

        <div className="text-center mb-8">
          <h2 className="text-3xl font-bold text-gray-800">Bộ Sưu Tập Huy Hiệu</h2>
          <p className="text-gray-500">Badge Collection</p>
          <div className="mt-4 bg-blue-50 inline-block px-6 py-2 rounded-full">
            <span className="text-blue-600 font-bold">Total Score: {totalPoints}</span>
          </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
          {BADGE_LEVELS.map((badge) => {
            const isUnlocked = totalPoints >= badge.score;
            return (
              <div 
                key={badge.name}
                className={`flex flex-col items-center p-4 rounded-xl border-2 transition-all ${
                  isUnlocked 
                    ? 'border-yellow-200 bg-yellow-50/50 shadow-md' 
                    : 'border-gray-100 bg-gray-50/50 grayscale opacity-60'
                }`}
              >
                <span className="text-4xl mb-2">{badge.icon}</span>
                <span className={`font-bold text-sm text-center ${isUnlocked ? badge.color : 'text-gray-400'}`}>
                  {badge.name}
                </span>
                <span className="text-xs text-gray-400 mt-1">{badge.score} pts</span>
                {isUnlocked && <span className="mt-2 text-[10px] uppercase font-bold text-green-600 tracking-wider">Unlocked</span>}
              </div>
            );
          })}
        </div>

        {nextBadge && (
           <div className="mt-8 text-center bg-gray-100/50 rounded-xl p-4">
              <p className="text-gray-600 text-sm">Next Badge: <strong>{nextBadge.name}</strong> in {nextBadge.score - totalPoints} points</p>
              <div className="w-full bg-gray-300 h-2 rounded-full mt-2 overflow-hidden">
                <div 
                  className="bg-blue-500 h-full transition-all duration-1000"
                  style={{ width: `${(totalPoints / nextBadge.score) * 100}%` }}
                />
              </div>
           </div>
        )}
      </div>
    </div>
  );

  // Views
  const renderGradeSelection = () => (
    <div className="animate-fade-in space-y-8">
      <div className="text-center space-y-4">
        <h1 className="text-5xl md:text-7xl font-extrabold tracking-tight text-white drop-shadow-lg">
          StudyBloom
        </h1>
        <p className="text-xl text-white font-semibold max-w-2xl mx-auto drop-shadow-md">
          Web học tiếng anh dành cho học sinh Cấp 2 & Cấp 3
        </p>
      </div>

      {Object.entries(GRADE_GROUPS).map(([groupName, grades]) => (
        <div key={groupName} className="bg-white/80 backdrop-blur-md rounded-3xl p-6 shadow-xl border border-white/60 hover:bg-white/90 transition-all">
          <h3 className="text-xl font-bold text-gray-800 mb-4 flex items-center">
            <span className="p-2 rounded-lg mr-3 bg-blue-100 text-blue-600">
              <Icons.Book />
            </span>
            {groupName}
          </h3>
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
            {grades.map((grade) => (
              <Button 
                key={grade} 
                onClick={() => setSelectedGrade(grade)}
                variant="outline"
                className="hover:scale-105 transition-transform bg-white/50 border-white hover:border-blue-300"
              >
                {grade.replace('Grade ', 'Lớp ')}
              </Button>
            ))}
          </div>
        </div>
      ))}
    </div>
  );

  const renderConfiguration = () => {
    // Determine which textbooks to show based on selected grade
    let availableTextbooks: string[] = [];
    if (selectedGrade) {
      const gradeNum = parseInt(selectedGrade.split(' ')[1]);
      if (gradeNum >= 6 && gradeNum <= 9) {
        availableTextbooks = TEXTBOOKS_BY_GRADE['Secondary'];
      } else {
        availableTextbooks = TEXTBOOKS_BY_GRADE['High'];
      }
    }

    return (
      <div className="max-w-4xl mx-auto space-y-6 animate-fade-in">
        <Button onClick={() => setSelectedGrade(null)} variant="outline" size="sm" className="bg-white/80 border-white text-gray-700">
          ← Quay lại
        </Button>

        <div className="bg-white/90 backdrop-blur-lg rounded-3xl p-8 shadow-2xl border border-white/50">
          <h2 className="text-3xl font-bold text-gray-800 mb-6">
            Thiết lập bài học: <span className="text-blue-600">{selectedGrade?.replace('Grade ', 'Lớp ')}</span>
          </h2>

          <div className="grid md:grid-cols-2 gap-8">
            {/* Column 1: Textbook */}
            <div>
              <label className="block text-gray-700 font-bold mb-3 uppercase text-xs tracking-wider">Giáo trình (Textbook)</label>
              <div className="space-y-2 max-h-64 overflow-y-auto pr-2 custom-scrollbar">
                <div 
                  onClick={() => setSelectedTextbook('')}
                  className={`cursor-pointer p-3 rounded-xl border-2 transition-all ${selectedTextbook === '' ? 'border-blue-500 bg-blue-50/50' : 'border-gray-100 bg-white/50 hover:border-blue-200'}`}
                >
                  <div className="font-bold text-gray-800">Tổng hợp (General)</div>
                </div>
                {availableTextbooks.map(tb => (
                  <div 
                    key={tb}
                    onClick={() => setSelectedTextbook(tb)}
                    className={`cursor-pointer p-3 rounded-xl border-2 transition-all ${selectedTextbook === tb ? 'border-blue-500 bg-blue-50/50' : 'border-gray-100 bg-white/50 hover:border-blue-200'}`}
                  >
                    <div className="font-bold text-gray-800">{tb.split('(')[0]}</div>
                    <div className="text-xs text-gray-500">{tb.includes('(') ? tb.split('(')[1].replace(')', '') : 'Phiên bản chuẩn'}</div>
                  </div>
                ))}
              </div>
            </div>

            {/* Column 2: Game Mode */}
            <div>
              <label className="block text-gray-700 font-bold mb-3 uppercase text-xs tracking-wider">Kỹ năng (Skill)</label>
              <div className="grid grid-cols-2 gap-3 mb-6">
                {Object.values(GameType).map((type) => (
                  <Button 
                    key={type}
                    variant={selectedGameType === type ? 'primary' : 'outline'} 
                    onClick={() => {
                        setSelectedGameType(type);
                        // Reset subskill if switching away from grammar
                        if (type !== GameType.Grammar) setSelectedSubSkill(null);
                        else setSelectedSubSkill(GrammarSubSkill.GrammarQuiz); // Default
                    }}
                    className="text-sm py-4 h-full"
                  >
                    {type}
                  </Button>
                ))}
              </div>

              {/* Sub-skill Selection for Grammar */}
              {selectedGameType === GameType.Grammar && (
                <div className="animate-fade-in bg-blue-50/50 p-4 rounded-xl border border-blue-100">
                  <label className="block text-blue-800 font-bold mb-3 uppercase text-xs tracking-wider">Loại bài tập (Exercise Type)</label>
                  <select 
                    value={selectedSubSkill || ''}
                    onChange={(e) => setSelectedSubSkill(e.target.value as GrammarSubSkill)}
                    className="w-full p-3 rounded-lg border-2 border-blue-200 focus:border-blue-500 focus:ring-0 bg-white text-gray-800 font-medium"
                  >
                    {Object.values(GrammarSubSkill).map((sub) => (
                        <option key={sub} value={sub}>{sub}</option>
                    ))}
                  </select>
                </div>
              )}
            </div>
          </div>

          <div className="mt-8 pt-6 border-t border-gray-100">
            <Button 
              onClick={handleStartGame} 
              fullWidth 
              size="lg" 
              variant="secondary"
              disabled={!selectedGameType}
              className="text-lg shadow-xl"
            >
              Bắt đầu ngay (Start Learning)
            </Button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="relative min-h-screen overflow-hidden font-sans text-gray-800">
      <BackgroundDecor />

      <div className="relative p-4 md:p-8 max-w-7xl mx-auto z-10">
        {/* Header */}
        <header className="flex justify-between items-center mb-8">
           <div className="font-black text-xl text-white/90 tracking-tight drop-shadow-md">StudyBloom</div>
           <div className="flex gap-2">
              <button 
                onClick={() => setShowBadges(true)}
                className="bg-white/90 backdrop-blur-sm px-4 py-2 rounded-full shadow-lg flex items-center gap-2 border border-white/50 hover:bg-white transition-colors"
              >
                {currentBadge ? (
                  <>
                    <span className="text-xl">{currentBadge.icon}</span>
                    <span className={`font-bold text-sm hidden sm:inline ${currentBadge.color}`}>{currentBadge.name}</span>
                  </>
                ) : (
                  <Icons.Badge />
                )}
                <span className="w-px h-4 bg-gray-200 mx-1"></span>
                <span className="font-bold text-gray-700 text-sm">{totalPoints} pts</span>
              </button>
           </div>
        </header>

        {/* Error Banner */}
        {error && (
          <div className="bg-red-100/90 backdrop-blur-sm border-l-4 border-red-500 text-red-700 p-4 rounded-lg mb-6 max-w-2xl mx-auto shadow-sm animate-bounce">
             <p className="font-bold">Lỗi (Error)</p>
             <p>{error}</p>
             <button onClick={() => setError(null)} className="underline mt-2">Đóng</button>
          </div>
        )}

        <main>
          {loading ? (
            <div className="flex flex-col items-center justify-center min-h-[50vh] animate-pulse">
              <div className="w-24 h-24 border-8 border-white border-t-blue-500 rounded-full animate-spin mb-8 shadow-2xl"></div>
              <h3 className="text-2xl font-bold text-white drop-shadow-md mb-2">Đang tạo bài học...</h3>
              <p className="text-white/80">AI đang chuẩn bị nội dung {selectedGameType}</p>
            </div>
          ) : !selectedGrade ? (
            renderGradeSelection()
          ) : !gameData ? (
            renderConfiguration()
          ) : finalScore !== null ? (
            <div className="flex items-center justify-center min-h-[60vh]">
              <ResultCard 
                score={finalScore} 
                total={gameData.questions.length * 2} 
                onRetry={() => { setFinalScore(null); }} 
                onHome={handleReset}
              />
            </div>
          ) : (
            <div className="animate-fade-in">
               <div className="flex items-center justify-between mb-6 max-w-3xl mx-auto">
                 <Button onClick={handleReset} variant="outline" size="sm" className="bg-white/80 border-white shadow-sm">Home</Button>
                 <span className="text-xs bg-white/80 px-3 py-1 rounded-full border border-white/50 shadow-sm text-gray-600 truncate max-w-[200px] backdrop-blur-sm">
                    {gameData.textbookContext} {gameData.subSkill ? `- ${gameData.subSkill}` : ''}
                 </span>
               </div>
               {renderGameComponent()}
            </div>
          )}
        </main>
      </div>

      <footer className="text-center text-white/80 mt-12 text-sm pb-4 relative z-10 drop-shadow-sm">
        <p>© 2025 StudyBloom. Aligned with MOET Curriculum.</p>
      </footer>

      {showBadges && renderBadgeModal()}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { QuestionData, GrammarSubSkill } from '../types';
import { Button } from './Button';

interface QuizGameProps {
  questions: QuestionData[];
  onComplete: (score: number) => void;
  subSkill?: GrammarSubSkill;
}

export const QuizGame: React.FC<QuizGameProps> = ({ questions, onComplete, subSkill }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  // Input mode state
  const [userInput, setUserInput] = useState("");
  const [isInputCorrect, setIsInputCorrect] = useState<boolean | null>(null);
  const [showSuggestion, setShowSuggestion] = useState(false);

  const currentQuestion = questions[currentIndex];
  const isInputMode = subSkill === GrammarSubSkill.SentenceTrans;

  // Reset state on question change
  useEffect(() => {
    setSelectedOption(null);
    setShowFeedback(false);
    setUserInput("");
    setIsInputCorrect(null);
    setShowSuggestion(false);
  }, [currentIndex]);

  if (!currentQuestion) return null;

  const handleOptionClick = (option: string) => {
    if (showFeedback) return;

    setSelectedOption(option);
    setShowFeedback(true);

    if (option === currentQuestion.correctAnswer) {
      setScore(prev => prev + 2); // 2 points per correct answer
    }
  };

  const handleInputCheck = () => {
    if (showFeedback) return;

    const normalize = (s: string) => s.toLowerCase().replace(/[.,!?;:]/g, '').trim().replace(/\s+/g, ' ');
    const user = normalize(userInput);
    const correct = normalize(currentQuestion.correctAnswer || "");

    const isCorrect = user === correct;
    setIsInputCorrect(isCorrect);
    setShowFeedback(true);

    if (isCorrect) {
      setScore(prev => prev + 2);
    }
  };

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      onComplete(score);
    }
  };

  const getButtonVariant = (option: string) => {
    if (!showFeedback) return selectedOption === option ? 'primary' : 'outline';
    if (option === currentQuestion.correctAnswer) return 'primary'; 
    if (option === selectedOption && option !== currentQuestion.correctAnswer) return 'danger';
    return 'outline';
  };

  const getButtonStyle = (option: string) => {
    if (!showFeedback) return "";
    if (option === currentQuestion.correctAnswer) return "!bg-green-500 !border-green-700 !text-white";
    return "";
  };

  return (
    <div className="max-w-2xl mx-auto w-full">
      {/* Progress Bar */}
      <div className="mb-6 bg-gray-200 rounded-full h-4 overflow-hidden">
        <div 
          className="bg-blue-500 h-full transition-all duration-500 ease-out"
          style={{ width: `${((currentIndex + 1) / questions.length) * 100}%` }}
        />
      </div>

      <div className="bg-white rounded-3xl shadow-xl p-6 md:p-8 border-b-8 border-gray-100">
        <div className="flex justify-between items-center mb-4">
          <span className="bg-blue-100 text-blue-800 text-xs font-bold px-3 py-1 rounded-full uppercase">
            Question {currentIndex + 1}/{questions.length}
          </span>
          <span className="text-gray-400 font-bold text-sm">{currentQuestion.topic}</span>
        </div>

        <h3 className="text-xl md:text-2xl font-bold text-gray-800 mb-8 leading-relaxed text-center">
          {currentQuestion.questionText}
        </h3>

        {/* RENDER FOR INPUT MODE (Sentence Transformation) */}
        {isInputMode ? (
          <div className="mb-6 space-y-4">
            <textarea
              value={userInput}
              onChange={(e) => setUserInput(e.target.value)}
              disabled={showFeedback}
              placeholder="Type your rewritten sentence here..."
              className={`w-full p-4 text-lg border-2 rounded-xl focus:ring-0 focus:border-blue-500 transition-colors resize-none h-32 ${
                isInputCorrect === true ? 'border-green-500 bg-green-50' : 
                isInputCorrect === false ? 'border-red-500 bg-red-50' : 
                'border-gray-300'
              }`}
            />

            {!showFeedback && (
              <div className="flex gap-3">
                 <Button onClick={handleInputCheck} disabled={!userInput.trim()} variant="primary" fullWidth>
                    Kiểm tra (Check)
                 </Button>
                 <Button 
                   onClick={() => setShowSuggestion(true)} 
                   variant="secondary" 
                   className="bg-yellow-500 hover:bg-yellow-600 border-yellow-700"
                 >
                    Gợi ý (Suggest) 💡
                 </Button>
              </div>
            )}

            {showSuggestion && !showFeedback && (
              <div className="bg-yellow-50 border border-yellow-200 p-4 rounded-xl animate-fade-in">
                <p className="text-yellow-800 font-bold mb-1">Gợi ý đáp án (Suggested Answer):</p>
                <p className="text-gray-700 italic select-all">{currentQuestion.correctAnswer}</p>
                <p className="text-xs text-yellow-600 mt-2">* Bạn có thể sao chép đáp án này nếu quá khó (You can copy this answer).</p>
              </div>
            )}

            {showFeedback && isInputCorrect === false && (
              <div className="bg-red-50 border border-red-200 p-4 rounded-xl">
                 <p className="text-red-700 font-bold">Đáp án đúng (Correct Answer):</p>
                 <p className="text-gray-800 text-lg">{currentQuestion.correctAnswer}</p>
              </div>
            )}
          </div>
        ) : (
        /* RENDER FOR MULTIPLE CHOICE */
          <div className="grid grid-cols-1 gap-4 mb-6">
            {currentQuestion.options?.map((option, idx) => (
              <Button
                key={idx}
                variant={getButtonVariant(option)}
                className={`text-left justify-start h-auto py-4 px-6 text-lg ${getButtonStyle(option)}`}
                onClick={() => handleOptionClick(option)}
                fullWidth
              >
                {option}
              </Button>
            ))}
          </div>
        )}

        {showFeedback && (
          <div className="bg-blue-50 border border-blue-100 rounded-xl p-4 mb-6 animate-fade-in">
            <p className="font-bold text-blue-800 mb-1">Giải thích (Explanation):</p>
            <p className="text-blue-700">{currentQuestion.explanation}</p>
          </div>
        )}

        <div className="flex justify-end">
          <Button 
            disabled={!showFeedback} 
            onClick={handleNext}
            size="lg"
            variant="secondary"
          >
            {currentIndex === questions.length - 1 ? 'Kết thúc (Finish)' : 'Câu tiếp theo (Next) →'}
          </Button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { QuestionData } from '../types';
import { Button } from './Button';

interface ListeningGameProps {
  questions: QuestionData[];
  onComplete: (score: number) => void;
}

interface ScriptSegment {
  text: string;
  speaker: string;
  isExclamation: boolean;
  isQuestion: boolean;
}

export const ListeningGame: React.FC<ListeningGameProps> = ({ questions, onComplete }) => {
  const [index, setIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [feedback, setFeedback] = useState<string | null>(null);
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);

  // Timer for reading questions
  const [readingCountdown, setReadingCountdown] = useState(30);

  // Important: Keep reference to active utterance to prevent Garbage Collection (Chrome bug)
  const activeUtteranceRef = useRef<SpeechSynthesisUtterance | null>(null);
  const cancelRef = useRef<boolean>(false);

  const current = questions[index];

  useEffect(() => {
    const updateVoices = () => {
      const voices = window.speechSynthesis.getVoices();
      // Prioritize Google voices or high-quality voices if possible
      const enVoices = voices.filter(v => v.lang.startsWith('en'));
      setAvailableVoices(enVoices);
    };

    updateVoices();
    window.speechSynthesis.onvoiceschanged = updateVoices;

    return () => {
      cancelRef.current = true;
      window.speechSynthesis.cancel();
      window.speechSynthesis.onvoiceschanged = null;
    };
  }, []);

  // Stop audio and reset timer when question changes
  useEffect(() => {
    cancelRef.current = true;
    window.speechSynthesis.cancel();
    setIsPlaying(false);
    setReadingCountdown(30);
  }, [index]);

  // Countdown timer effect
  useEffect(() => {
    if (readingCountdown > 0) {
      const timer = setTimeout(() => {
        setReadingCountdown(prev => prev - 1);
      }, 1000);
      return () => clearTimeout(timer);
    }
  }, [readingCountdown]);

  if (!current) return null;

  const parseScript = (text: string): ScriptSegment[] => {
    const segments: ScriptSegment[] = [];
    if (!text) return segments;

    const lines = text.split(/\n+/);

    lines.forEach(line => {
      line = line.trim();
      if (!line) return;

      let speaker = 'Narrator';
      let content = line;

      // Try to parse "Speaker: Content"
      const colonIdx = line.indexOf(':');
      if (colonIdx > -1 && colonIdx < 20) {
        speaker = line.substring(0, colonIdx).trim();
        content = line.substring(colonIdx + 1).trim();
      }

      // Regex to split sentences but keep punctuation
      const sentenceRegex = /([^{.!?]+[.!?]+)|([^{.!?]+$)/g;
      const matches = content.match(sentenceRegex);

      if (matches) {
        matches.forEach(m => {
          const s = m.trim();
          if (s) {
            segments.push({
              text: s,
              speaker,
              isExclamation: s.includes('!'),
              isQuestion: s.includes('?')
            });
          }
        });
      }
    });

    return segments;
  };

  const playAudio = () => {
    if (!current.listeningScript) return;

    cancelRef.current = false;
    window.speechSynthesis.cancel();
    setIsPlaying(true);

    const segments = parseScript(current.listeningScript);

    if (segments.length === 0) {
        setIsPlaying(false);
        return;
    }

    const uniqueSpeakers = Array.from(new Set(segments.map(s => s.speaker)));
    const speakerConfig: Record<string, { voice: SpeechSynthesisVoice | null, pitch: number }> = {};

    uniqueSpeakers.forEach((spk, idx) => {
       const voice = availableVoices.length > 0 ? availableVoices[idx % availableVoices.length] : null;
       // Vary pitch slightly for different speakers
       const pitch = 1.0 + ((idx % 3) - 1) * 0.1; 
       speakerConfig[spk] = { voice, pitch };
    });

    let currentSegmentIdx = 0;

    const speakNext = () => {
      if (cancelRef.current || currentSegmentIdx >= segments.length) {
        setIsPlaying(false);
        activeUtteranceRef.current = null;
        return;
      }

      const seg = segments[currentSegmentIdx];
      const config = speakerConfig[seg.speaker] || { voice: null, pitch: 1.0 };

      const u = new SpeechSynthesisUtterance(seg.text);
      activeUtteranceRef.current = u; // Prevent GC

      u.lang = 'en-US';

      // Make voice more emotional/enthusiastic
      let rate = 1.0; // Slightly faster than default for energy
      let pitch = config.pitch;

      if (seg.isExclamation) {
        // High energy for exclamations
        pitch += 0.25;
        rate += 0.1;
        u.volume = 1.0;
      } else if (seg.isQuestion) {
        // Raising pitch for questions
        pitch += 0.15; 
      }

      if (config.voice) u.voice = config.voice;
      u.pitch = Math.max(0.5, Math.min(2, pitch));
      u.rate = rate;

      u.onend = () => {
        currentSegmentIdx++;
        let pause = 300; // Shorter pause for better flow
        if (seg.isExclamation) pause = 500;

        if (currentSegmentIdx < segments.length) {
            if (segments[currentSegmentIdx].speaker !== seg.speaker) {
                pause = 600; // Pause between speakers
            }
        }

        if (!cancelRef.current) {
             setTimeout(speakNext, pause);
        }
      };

      u.onerror = (e) => {
        console.warn("TTS Event Error:", e);
        if (e.error !== 'interrupted' && e.error !== 'canceled') {
           setIsPlaying(false);
        }
      };

      window.speechSynthesis.speak(u);
    };

    speakNext();
  };

  const handleAnswer = (option: string) => {
    if (feedback) return;
    const isCorrect = option === current.correctAnswer;
    if (isCorrect) setScore(s => s + 2); // 2 Points
    setFeedback(isCorrect ? "Correct! 🎉" : `Incorrect. Answer: ${current.correctAnswer}`);

    setTimeout(() => {
      setFeedback(null);
      if (index < questions.length - 1) {
        setIndex(i => i + 1);
      } else {
        onComplete(score + (isCorrect ? 2 : 0));
      }
    }, 2500);
  };

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-3xl p-8 shadow-xl">
      <div className="text-center mb-8">
        <h3 className="text-xl font-bold text-gray-600 mb-4">Luyện Nghe (Question {index + 1}/{questions.length})</h3>

        <div className="flex flex-col items-center relative">
            {readingCountdown > 0 ? (
               <div className="flex flex-col items-center animate-fade-in">
                  <div className="text-4xl font-black text-blue-600 mb-2">{readingCountdown}s</div>
                  <p className="text-sm font-bold text-gray-500 mb-4">Đọc kỹ câu hỏi trước khi nghe (Read carefully)</p>
                  <Button 
                    onClick={() => setReadingCountdown(0)}
                    variant="outline"
                    size="sm"
                    className="text-xs"
                  >
                    Bỏ qua (Skip Wait)
                  </Button>
               </div>
            ) : (
                <>
                    <button 
                    onClick={playAudio}
                    disabled={isPlaying}
                    className={`rounded-full p-6 transition-all transform active:scale-95 ${isPlaying ? 'bg-indigo-100 text-indigo-400 animate-pulse ring-4 ring-indigo-50' : 'bg-blue-100 hover:bg-blue-200 text-blue-600 shadow-lg hover:shadow-blue-200 animate-bounce'}`}
                    >
                    <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
                    </svg>
                    </button>
                    <p className="mt-3 text-sm font-bold text-gray-500 uppercase tracking-wide">
                        {isPlaying ? "Đang đọc... (Listening...)" : "Bấm để nghe (Play Audio)"}
                    </p>
                </>
            )}
        </div>
      </div>

      <div className={`bg-gray-50 rounded-2xl p-6 mb-6 border border-gray-100 transition-all duration-500 ${readingCountdown > 0 ? 'ring-2 ring-blue-300 scale-105' : ''}`}>
        <p className="text-xl font-medium text-gray-800 text-center leading-relaxed">{current.questionText}</p>
      </div>

      <div className="grid gap-4">
        {current.options?.map((opt, i) => (
          <Button 
            key={i} 
            onClick={() => handleAnswer(opt)} 
            variant="outline" 
            fullWidth 
            disabled={!!feedback || readingCountdown > 0}
            className={`text-lg py-4 hover:border-blue-400 hover:bg-blue-50 ${readingCountdown > 0 ? 'opacity-50 cursor-not-allowed' : ''}`}
          >
            {opt}
          </Button>
        ))}
      </div>

      {feedback && (
        <div className={`mt-6 p-4 rounded-xl text-center font-bold text-lg animate-fade-in-up ${feedback.includes('Correct') ? 'bg-green-100 text-green-700 border border-green-200' : 'bg-red-100 text-red-700 border border-red-200'}`}>
          {feedback}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { QuestionData } from '../types';
import { Button } from './Button';

interface SpeakingGameProps {
  questions: QuestionData[];
  onComplete: (score: number) => void;
}

export const SpeakingGame: React.FC<SpeakingGameProps> = ({ questions, onComplete }) => {
  const [index, setIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState("");
  const [feedback, setFeedback] = useState<string | null>(null);

  const recognitionRef = useRef<any>(null);
  const shouldListenRef = useRef<boolean>(false); // Helper to track intent

  const current = questions[index];

  // @ts-ignore - simple handling for webkitSpeechRecognition
  const Recognition = window.SpeechRecognition || window.webkitSpeechRecognition;

  useEffect(() => {
    // Cleanup on unmount or question change
    if (recognitionRef.current) {
      shouldListenRef.current = false; // Stop the auto-restart loop
      recognitionRef.current.stop();
      setIsListening(false);
    }
  }, [index]);

  if (!current) return null;

  const toggleRecord = () => {
    if (isListening) {
      stopRecording();
    } else {
      startRecording();
    }
  };

  const startRecording = () => {
    if (!Recognition) {
      alert("Trình duyệt của bạn không hỗ trợ nhận diện giọng nói (hãy thử dùng Google Chrome).");
      return;
    }

    // Indicate that we INTEND to listen, so if it stops randomly, we restart
    shouldListenRef.current = true;

    const recognition = new Recognition();
    recognition.lang = 'en-US';
    // Continuous allows it to not stop after a short pause
    recognition.continuous = true;
    // Interim results allows us to see what is being said in real-time
    recognition.interimResults = true;
    recognition.maxAlternatives = 1;

    recognitionRef.current = recognition;

    setIsListening(true);
    if (!transcript) setTranscript(""); 
    setFeedback("Đang lắng nghe... (Listening...)");

    try {
      recognition.start();
    } catch (e) {
      console.error(e);
      setIsListening(false);
      setFeedback("Lỗi khởi động micro. Vui lòng tải lại trang.");
    }

    recognition.onresult = (event: any) => {
      let finalTranscript = '';
      let interimTranscript = '';

      for (let i = event.resultIndex; i < event.results.length; ++i) {
        if (event.results[i].isFinal) {
          finalTranscript += event.results[i][0].transcript;
        } else {
          interimTranscript += event.results[i][0].transcript;
        }
      }

      // Update display with current best guess
      const currentText = finalTranscript || interimTranscript;
      setTranscript(currentText);

      // Check automatically if the user has said the target sentence correctly
      // Only auto-stop if match is very strong to avoid premature stopping
      if (checkMatch(currentText)) {
          // Keep listening flag true so UI doesn't jump, but handle success logic
          stopRecording(true); // Success stop
      }
    };

    recognition.onerror = (event: any) => {
      console.error("Speech Recognition Error:", event.error);
      if (event.error === 'no-speech') {
        // Ignore no-speech errors in continuous mode usually
        return; 
      }

      // Only show error feedback if we are actually trying to listen
      if (shouldListenRef.current) {
          if (event.error === 'not-allowed' || event.error === 'service-not-allowed') {
            setFeedback("Vui lòng cấp quyền truy cập Micro trên trình duyệt!");
            shouldListenRef.current = false;
            setIsListening(false);
          } else if (event.error === 'audio-capture') {
            setFeedback("Không tìm thấy Micro. Vui lòng kiểm tra thiết bị.");
            shouldListenRef.current = false;
            setIsListening(false);
          } else if (event.error === 'network') {
             setFeedback("Lỗi kết nối mạng.");
             shouldListenRef.current = false;
             setIsListening(false);
          }
      }
    };

    recognition.onend = () => {
        // Critical: If we didn't mean to stop (intent is true), restart immediately.
        // This fixes the issue where browser stops listening when user pauses too long.
        if (shouldListenRef.current) {
            try {
                recognition.start();
            } catch (e) {
                // Ignore start errors (like if it's already started)
            }
        } else {
            setIsListening(false);
        }
    };
  };

  const stopRecording = (isSuccess = false) => {
    // Set intent to false so onend doesn't restart
    shouldListenRef.current = false;

    if (recognitionRef.current) {
        recognitionRef.current.stop();
        // recognitionRef.current = null; // Don't nullify immediately to allow graceful shutdown
    }
    setIsListening(false);

    if (isSuccess) {
       setFeedback("Tuyệt vời! Chính xác 100% 🎉");
       setScore(s => s + 2); // 2 Points
       setTimeout(nextQuestion, 2000);
    } else {
       // Manual stop
       if (!transcript || transcript.trim().length === 0) {
           setFeedback("Bạn chưa nói gì cả (No input detected).");
           return;
       }
       checkPronunciation(transcript);
    }
  };

  const normalizeText = (s: string) => s.toLowerCase().replace(/[.,!?]/g, '').trim();

  const checkMatch = (spoken: string): boolean => {
    const target = current.speakingTarget || "";
    const nSpoken = normalizeText(spoken);
    const nTarget = normalizeText(target);

    // Safety check: Don't match empty strings
    if (!nSpoken || nSpoken.length < 2) return false;

    // 1. Exact match
    if (nSpoken === nTarget) return true;

    // 2. User said the target phrase (plus maybe some background noise or extra words)
    if (nSpoken.includes(nTarget)) return true;

    // 3. Reverse inclusion (Target contains spoken)
    // ONLY allow this if spoken is at least 80% of the target length.
    // This prevents "I" matching "I go to school".
    if (nTarget.includes(nSpoken)) {
        return nSpoken.length >= nTarget.length * 0.8;
    }

    return false;
  };

  const checkPronunciation = (spoken: string) => {
    // Relaxed check for manual stop
    if (checkMatch(spoken)) {
      setFeedback("Tuyệt vời! Chính xác 100% 🎉");
      setScore(s => s + 2); // 2 Points
      setTimeout(nextQuestion, 2000);
    } else {
      setFeedback(`Gần đúng! Bạn nói: "${spoken || '...'}" - Hãy thử lại!`);
    }
  };

  const nextQuestion = () => {
    setFeedback(null);
    setTranscript("");
    if (index < questions.length - 1) setIndex(i => i + 1);
    else onComplete(score);
  };

  if (!Recognition) return <div className="text-center p-8">Trình duyệt không hỗ trợ Speaking.</div>;

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-3xl p-8 shadow-xl text-center">
      <span className="text-sm font-bold text-gray-400">Câu {index + 1}/{questions.length}</span>
      <h3 className="text-2xl font-bold text-gray-800 mt-2 mb-6">{current.questionText}</h3>

      <div className="bg-blue-50 p-6 rounded-2xl mb-8 border-2 border-blue-100">
        <p className="text-3xl font-extrabold text-blue-600 leading-tight">{current.speakingTarget}</p>
      </div>

      <div className="mb-8 min-h-[5rem] bg-gray-50 rounded-xl p-4 border border-gray-100 flex items-center justify-center">
        {transcript ? (
            <p className="text-gray-700 text-lg font-medium">"{transcript}"</p>
        ) : (
            <p className="text-gray-400 italic text-sm">Nội dung bạn nói sẽ hiện ở đây...</p>
        )}
      </div>

      {feedback && <p className={`font-bold mb-4 animate-pulse ${feedback.includes('Tuyệt') ? 'text-green-600' : 'text-orange-500'}`}>{feedback}</p>}

      <div className="flex gap-4 justify-center items-center">
        <Button 
          onClick={toggleRecord} 
          variant={isListening ? 'danger' : 'primary'}
          size="lg"
          className={`rounded-full w-24 h-24 flex items-center justify-center transition-all ${isListening ? 'ring-4 ring-red-200 scale-110' : 'hover:scale-105'}`}
        >
          {isListening ? (
             <div className="flex flex-col items-center">
                <div className="w-8 h-8 bg-white rounded-sm animate-pulse"></div>
                <span className="text-[10px] mt-2 font-bold uppercase">Stop</span>
             </div>
          ) : (
            <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          )}
        </Button>
      </div>
      <p className="text-xs text-gray-400 mt-4">
