import { GoogleGenAI, Type, Modality } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Schemas for structured output
const evaluationSchema = {
    type: Type.OBJECT,
    properties: {
        fluencyAndCoherence: {
            type: Type.OBJECT,
            properties: {
                score: { type: Type.INTEGER, description: "Score from 1-9 (whole numbers only)." },
                feedback: {
                    type: Type.OBJECT,
                    properties: {
                        strengths: { type: Type.STRING, description: "Detailed description of what the user did well." },
                        areasForImprovement: { type: Type.STRING, description: "Detailed, actionable advice and examples of how to reach the next band score." }
                    }
                }
            }
        },
        lexicalResource: {
            type: Type.OBJECT,
            properties: {
                score: { type: Type.INTEGER },
                feedback: {
                    type: Type.OBJECT,
                    properties: {
                        strengths: { type: Type.STRING },
                        areasForImprovement: { type: Type.STRING }
                    }
                }
            }
        },
        grammaticalRangeAndAccuracy: {
            type: Type.OBJECT,
            properties: {
                score: { type: Type.INTEGER },
                feedback: {
                    type: Type.OBJECT,
                    properties: {
                        strengths: { type: Type.STRING },
                        areasForImprovement: { type: Type.STRING }
                    }
                }
            }
        },
        pronunciation: {
            type: Type.OBJECT,
            properties: {
                score: { type: Type.INTEGER },
                feedback: {
                    type: Type.OBJECT,
                    properties: {
                        strengths: { type: Type.STRING },
                        areasForImprovement: { type: Type.STRING }
                    }
                }
            }
        },
        overallScore: { type: Type.NUMBER, description: "Average of the 4 criteria, rounded to nearest 0.5" }
    }
};

const modelAnswerSchema = {
    type: Type.OBJECT,
    properties: {
        answer: { type: Type.STRING, description: "A Band 8.5+ model answer for the topic." },
        vocabulary: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    term: { type: Type.STRING },
                    definition: { type: Type.STRING }
                }
            },
            description: "List of 5-7 advanced vocabulary terms or idioms used in the model answer."
        }
    }
};

const questionsSchema = {
    type: Type.OBJECT,
    properties: {
        title: { type: Type.STRING, description: "Title of the Part 3 topic" },
        prompt: { type: Type.STRING, description: "Introductory sentence for the discussion" },
        points: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "List of 4-5 complex discussion questions"
        }
    }
};

const highlightsSchema = {
    type: Type.OBJECT,
    properties: {
        highlights: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "List of good vocabulary words or phrases found in the input text."
        }
    }
};

export default async function handler(req, res) {
    if (req.method !== 'POST') {
        return res.status(405).json({ error: 'Method Not Allowed' });
    }

    const { type, payload } = req.body;

    try {
        if (type === 'transcribe') {
            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: {
                    parts: [
                        { inlineData: { mimeType: payload.mimeType, data: payload.audio } },
                        { text: "Transcribe this audio of an IELTS Speaking test candidate exactly. Do not add descriptions." }
                    ]
                }
            });
            return res.status(200).json({ transcription: response.text });
        }

        if (type === 'evaluate') {
            const prompt = `Evaluate the following IELTS Speaking response based on the topic: "${payload.topic.title || payload.topic.prompt}".

            Response: "${payload.transcription}"

            Task: Provide a highly detailed and rigorous evaluation based on official IELTS band descriptors. 
            For EACH of the four criteria:
            1. Strengths: Be specific about which parts of the response demonstrated good skills.
            2. Areas for Improvement: Provide actionable, step-by-step advice on how to improve. Use specific examples from their response and show how they could be rephrased or corrected to reach a higher band (e.g., if they are Band 6, tell them exactly what is needed for Band 7).

            The user wants very detailed feedback to improve their score. Be strict and professional.`;

            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: evaluationSchema,
                    thinkingConfig: { thinkingBudget: 0 }
                }
            });
            return res.status(200).json(JSON.parse(response.text));
        }

        if (type === 'modelAnswer') {
            const prompt = `Generate a Band 9 model answer for the IELTS Speaking topic: "${payload.topic.title || payload.topic.prompt}".

            Context/Questions:
            ${JSON.stringify(payload.topic.points)}

            The answer should be natural, idiomatic, and demonstrate high-level vocabulary.
            Also list 5-7 key vocabulary terms used in the answer with definitions.`;

            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: modelAnswerSchema,
                    thinkingConfig: { thinkingBudget: 0 }
                }
            });
            return res.status(200).json(JSON.parse(response.text));
        }

        if (type === 'highlights') {
            const prompt = `Identify the best vocabulary (B2-C2 level words, idioms, collocations) used in this text. Return them as a simple list of strings.

            Text: "${payload.transcription}"`;

            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: highlightsSchema,
                    thinkingConfig: { thinkingBudget: 0 }
                }
            });
            return res.status(200).json(JSON.parse(response.text));
        }

        if (type === 'generateQuestions') {
            if (payload.part === 'part3') {
                const context = payload.contextTopic ? `The user just finished talking about: "${payload.contextTopic}" in Part 2.` : "General topics.";
                const prompt = `Generate 4-5 IELTS Speaking Part 3 discussion questions. 
                ${context}
                Part 3 questions should be abstract, focusing on society, trends, and general opinions. 
                Avoid personal "do you like" questions. Focus on "Why", "How", "Impact of...", "Future of...".

                Output JSON with a title, a short prompt intro, and the list of questions as 'points'.`;

                const response = await ai.models.generateContent({
                    model: 'gemini-2.5-flash',
                    contents: prompt,
                    config: {
                        responseMimeType: "application/json",
                        responseSchema: questionsSchema
                    }
                });
                return res.status(200).json(JSON.parse(response.text));
            }
        }

        if (type === 'tts') {
            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash-preview-tts',
                contents: {
                    parts: [{ text: payload.text }]
                },
                config: {
                    responseModalities: [Modality.AUDIO],
                    speechConfig: {
                        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } }
                    }
                }
            });

            const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
            if (!audioData) throw new Error("No audio data generated");

            return res.status(200).json({ audio: audioData });
        }

        return res.status(400).json({ error: 'Invalid request type' });

    } catch (error) {
        console.error('API Error:', error);
        return res.status(500).json({ error: error.message });
    }
}

