                ) : appState === AppState.FEEDBACK ? (
                    <div className="w-full animate-fade-in">
                        <div className="flex flex-col md:flex-row gap-8">
                            <div className="md:w-1/3 flex flex-col gap-6">
                                <div className="tet-card p-10 text-center">
                                    <h3 className="text-2xl font-bold text-amber-300 mb-4">Overall Band</h3>
                                    <div className="text-9xl font-black text-amber-400">{evaluation.overallScore}</div>
                                </div>
                                <button onClick={() => setAppState(AppState.HOME)} className="bg-tet-gold py-6 rounded-xl font-bold text-xl">Practice Again</button>
                            </div>
                            <div className="md:w-2/3 tet-card p-10 max-h-[80vh] overflow-y-auto custom-scrollbar">
                                <h2 className="text-3xl font-bold text-amber-300 mb-10 border-b pb-4">Detailed Feedback (Vietnamese)</h2>
                                {['fluencyAndCoherence', 'lexicalResource', 'grammaticalRangeAndAccuracy', 'pronunciation'].map(k => (
                                    <div key={k} className="mb-10 p-6 bg-red-950/40 rounded-xl border border-amber-900/50">
