                                            <span className="bg-amber-500 text-red-950 px-4 py-1 rounded-full font-bold">Band {evaluation[k].score}</span>
                                        </div>
                                        <div className="grid md:grid-cols-2 gap-6">
                                            <div>
                                                <p className="text-green-400 font-bold mb-1">Điểm mạnh:</p>
                                                <p className="text-amber-50/80">{evaluation[k].feedback.strengths}</p>
                                            </div>
                                            <div>
                                                <p className="text-orange-400 font-bold mb-1">Cần cải thiện:</p>
                                                <p className="text-amber-50/80">{evaluation[k].feedback.areasForImprovement}</p>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                ) : null}
            </main>
        </div>
    </div>
  );
};

const Timer = ({ duration, onFinish }) => {
  const [timeLeft, setTimeLeft] = useState(duration);
  useEffect(() => {
    if (timeLeft === 0) { onFinish(); return; }
    const interval = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    return () => clearInterval(interval);
  }, [timeLeft]);
  const m = String(Math.floor(timeLeft / 60)).padStart(2, '0');
  const s = String(timeLeft % 60).padStart(2, '0');
  return <div className="text-8xl font-black text-amber-400 font-mono">{m}:{s}</div>;
};

