        lexicalResource: { type: Type.OBJECT, properties: { score: { type: Type.INTEGER }, feedback: { type: Type.OBJECT, properties: { strengths: { type: Type.STRING }, areasForImprovement: { type: Type.STRING } } } } },
        grammaticalRangeAndAccuracy: { type: Type.OBJECT, properties: { score: { type: Type.INTEGER }, feedback: { type: Type.OBJECT, properties: { strengths: { type: Type.STRING }, areasForImprovement: { type: Type.STRING } } } } },
        pronunciation: { type: Type.OBJECT, properties: { score: { type: Type.INTEGER }, feedback: { type: Type.OBJECT, properties: { strengths: { type: Type.STRING }, areasForImprovement: { type: Type.STRING } } } } },
        overallScore: { type: Type.NUMBER }
    },
    required: ["fluencyAndCoherence", "lexicalResource", "grammaticalRangeAndAccuracy", "pronunciation", "overallScore"]
};

const sampleSchema = {
    type: Type.OBJECT,
    properties: {
        sampleText: { type: Type.STRING, description: "A Band 8.5+ answer. Wrap collocations/idioms in [[term|vietnamese_meaning]] tags." }
    },
    required: ["sampleText"]
};

export default async function handler(req, res) {
    const { type, payload, customKey } = req.body;
    const finalKey = customKey || process.env.API_KEY;

    if (!finalKey) return res.status(400).json({ error: "Missing API Key" });

    const ai = new GoogleGenAI({ apiKey: finalKey });

    try {
        if (type === 'transcribe') {
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: { parts: [{ inlineData: { mimeType: payload.mimeType, data: payload.audio } }, { text: "Transcribe the following IELTS response exactly as spoken, including fillers like um, ah if present. Output only the transcription text." }] }
            });
            return res.status(200).json({ transcription: response.text });
        }

        if (type === 'evaluate') {
            const prompt = `Evaluate the following complete IELTS Speaking session based on official IELTS band descriptors. 
            Topic: "${payload.topic.title}"

            FULL TRANSCRIPT:
            ${payload.transcription}

            IMPORTANT: All feedback MUST be in Vietnamese. Provide detailed, specific advice for each category. Be encouraging but realistic.`;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
                config: { 
                    responseMimeType: "application/json", 
                    responseSchema: evaluationSchema,
                }
            });
            return res.status(200).json(JSON.parse(response.text));
        }

        if (type === 'getSample') {
            const prompt = `Generate a Band 8.5-9.0 sample answer for this IELTS Part 2 cue card:
            "${payload.topic.title}"
            Prompt details: ${payload.topic.points.join(', ')}

            Format:
            Highlight the BEST vocabulary, collocations, and idioms by wrapping them in this specific format: [[word or phrase|Nghĩa tiếng Việt]].
            Aim for natural, idiomatic English. The response should be roughly 250-300 words.`;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: sampleSchema
                }
            });
            return res.status(200).json(JSON.parse(response.text));
        }

        if (type === 'tts') {
            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash-preview-tts',
                contents: { parts: [{ text: `Say in a professional, slightly British IELTS examiner voice: ${payload.text}` }] },
                config: { 
                    responseModalities: [Modality.AUDIO], 
                    speechConfig: { 
                        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Charon' } } 
                    } 
                }
            });
            return res.status(200).json({ audio: response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data });
        }
    } catch (e) { 
        return res.status(500).json({ error: e.message }); 
    }
}

import React, { useState, useCallback, useEffect, useRef } from 'react';
import ReactDOM from 'react-dom/client';

const AppState = {
  AUTH: 'auth',
  HOME: 'home',
  PREPARATION: 'preparation',
  SPEAKING: 'speaking',
  TRANSITION: 'transition',
  EVALUATING: 'evaluating',
  FEEDBACK: 'feedback',
};

const TestMode = {
  PART1: 'part1',
  PART2: 'part2',
  PART3: 'part3',
  FULL: 'full'
};

const CUE_CARDS = [
  {
    title: "Describe a special festival in your country",
    prompt: "Describe a special festival that is celebrated in your country.",
    points: ["When and where it is celebrated", "What people do during this festival", "What traditional foods are eaten", "And explain why you like or dislike this festival."]
  },
  {
    title: "Describe a successful person you admire",
    prompt: "Describe a successful person you admire.",
    points: ["Who this person is", "How you know about them", "What they have achieved", "And explain why you admire them."]
  }
];

const PART1_QUESTIONS = [
    "Tell me about your hometown.",
    "Do you work or are you a student?",
    "What do you like to do in your free time?",
    "Let's talk about food. What is your favorite traditional dish?"
];

const PART3_QUESTIONS = [
    "How have festivals changed in your country over the last few decades?",
    "Do you think international festivals are more important than local ones?",
    "How does success influence a person's personality?"
];

const BlossomFall = () => {
  const petals = Array.from({ length: 40 }).map((_, i) => {
    const style = {
      left: `${Math.random() * 100}vw`,
      animationDelay: `${Math.random() * 8}s, ${Math.random() * 4}s`,
      opacity: Math.random() * 0.7 + 0.3,
      fontSize: `${Math.random() * 1 + 0.8}rem`,
      color: '#fbbf24',
    };
    return <div key={i} className="blossom" style={style}>🌼</div>;
  });
  return <div className="fixed inset-0 pointer-events-none z-0 overflow-hidden">{petals}</div>;
};

const App = () => {
  const [appState, setAppState] = useState(AppState.AUTH);
  const [apiKey, setApiKey] = useState(localStorage.getItem('user_api_key') || '');
  const [mode, setMode] = useState(null);
  const [currentStage, setCurrentStage] = useState(null); 
  const [questions, setQuestions] = useState([]);
  const [questionIndex, setQuestionIndex] = useState(0);
  const [sessionData, setSessionData] = useState([]); 
  const [cueCard, setCueCard] = useState(null);
  const [evaluation, setEvaluation] = useState(null);
  const [sampleAnswer, setSampleAnswer] = useState(null);
  const [loadingMsg, setLoadingMsg] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const [isReading, setIsReading] = useState(false);
  const [showVocabBank, setShowVocabBank] = useState(false);
  const [savedVocab, setSavedVocab] = useState(JSON.parse(localStorage.getItem('saved_vocab') || '[]'));

  const mediaRecorderRef = useRef(null);
  const audioChunksRef = useRef([]);

  const callApi = async (type, payload) => {
      const response = await fetch('/api/gemini', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ type, payload, customKey: apiKey }),
      });
      if (!response.ok) throw new Error('API Error');
      return response.json();
  };

  const speakQuestion = async (text) => {
      setIsReading(true);
      try {
          const res = await callApi('tts', { text });
          if (res.audio) {
              const audio = new Audio(`data:audio/wav;base64,${res.audio}`);
              audio.onended = () => setIsReading(false);
              audio.play();
          } else {
              setIsReading(false);
          }
      } catch (e) {
          setIsReading(false);
      }
  };

  const saveToVocab = (term, definition) => {
      if (savedVocab.find(v => v.term === term)) return;
      const newList = [...savedVocab, { term, definition, date: new Date().toLocaleDateString() }];
      setSavedVocab(newList);
      localStorage.setItem('saved_vocab', JSON.stringify(newList));
  };

  const startRecording = async () => {
      audioChunksRef.current = [];
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorderRef.current = new MediaRecorder(stream);
      mediaRecorderRef.current.ondataavailable = (e) => audioChunksRef.current.push(e.data);
      mediaRecorderRef.current.onstop = handleRecordingStop;
      mediaRecorderRef.current.start();
      setIsRecording(true);
  };

  const stopRecording = () => {
      if (mediaRecorderRef.current) {
          mediaRecorderRef.current.stop();
          setIsRecording(false);
      }
  };

  const handleRecordingStop = async () => {
      const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
      const base64 = await new Promise((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => {
              if (typeof reader.result === 'string') {
                  resolve(reader.result.split(',')[1]);
              }
          };
          reader.readAsDataURL(audioBlob);
      });

      setLoadingMsg('Đang nhận diện giọng nói...');
      setAppState(AppState.TRANSITION);
      try {
          const { transcription } = await callApi('transcribe', { audio: base64, mimeType: 'audio/webm' });
          const currentQuestion = currentStage === 'p2' ? (cueCard?.title || '') : (questions[questionIndex] || '');

          const newData = [...sessionData, { question: String(currentQuestion), transcription: String(transcription) }];
          setSessionData(newData);

          if (mode === TestMode.FULL) {
              if (currentStage === 'p1') {
                  if (questionIndex >= questions.length - 1) {
                      startPart2();
                  } else {
                      setQuestionIndex(prev => prev + 1);
                      setAppState(AppState.SPEAKING);
                  }
              } else if (currentStage === 'p2') {
                  startPart3();
              } else if (currentStage === 'p3') {
                  if (questionIndex >= questions.length - 1) {
                      finalizeTest(newData);
                  } else {
                      setQuestionIndex(prev => prev + 1);
                      setAppState(AppState.SPEAKING);
                  }
              }
          } else {
              if (mode === TestMode.PART2 || questionIndex >= questions.length - 1) {
                  finalizeTest(newData);
              } else {
                  setQuestionIndex(prev => prev + 1);
                  setAppState(AppState.SPEAKING);
              }
          }
      } catch (e) {
          console.error(e);
          setAppState(AppState.HOME);
      }
  };

  const finalizeTest = async (allData) => {
      setLoadingMsg('Đang chấm điểm dựa trên tiêu chí IELTS...');
      setAppState(AppState.EVALUATING);
      try {
          const fullTranscript = allData.map(d => `Examiner: ${d.question}\nCandidate: ${d.transcription}`).join('\n\n');
          const result = await callApi('evaluate', { 
              transcription: fullTranscript, 
              topic: { title: mode === TestMode.FULL ? "Full Speaking Test" : "Practice Session" } 
          });
          setEvaluation(result);

          const p2Data = allData.find(d => d.question.toLowerCase().includes('describe'));
          if (p2Data || mode === TestMode.PART2) {
              const sampleRes = await callApi('getSample', { topic: cueCard || CUE_CARDS[0] });
              setSampleAnswer(sampleRes);
          }

          setAppState(AppState.FEEDBACK);
      } catch (e) {
          console.error(e);
          setAppState(AppState.HOME);
      }
  };

  const startPart1 = () => {
      setCurrentStage('p1');
      setQuestions(PART1_QUESTIONS);
      setQuestionIndex(0);
      setAppState(AppState.SPEAKING);
  };

  const startPart2 = () => {
      setCurrentStage('p2');
      setCueCard(CUE_CARDS[Math.floor(Math.random() * CUE_CARDS.length)]);
      setAppState(AppState.PREPARATION);
  };

  const startPart3 = () => {
      setCurrentStage('p3');
      setQuestions(PART3_QUESTIONS);
      setQuestionIndex(0);
      setAppState(AppState.SPEAKING);
  };

  const handleModeSelect = (m) => {
      setMode(m);
      setSessionData([]);
      setSampleAnswer(null);
      if (m === TestMode.PART1) startPart1();
      else if (m === TestMode.PART2) startPart2();
      else if (m === TestMode.PART3) startPart3();
      else if (m === TestMode.FULL) startPart1();
  };

  const renderText = (val) => {
    if (val === undefined || val === null) return '';
    if (typeof val === 'object') return JSON.stringify(val);
    return String(val);
  };

  const renderSampleWithHighlights = (text) => {
      if (!text) return null;
      const parts = text.split(/(\[\[.*?\]\])/g);
      return parts.map((part, i) => {
          if (part.startsWith('[[') && part.endsWith(']]')) {
              const content = part.slice(2, -2);
              const [term, definition] = content.split('|');
              return (
                  <span 
                    key={i} 
                    className="highlight-btn" 
                    title={definition} 
                    onClick={() => saveToVocab(term, definition)}
                  >
                      {term}
                  </span>
              );
          }
          return part;
      });
  };

  return (
    <div className="min-h-screen p-4 md:p-8 relative">
        <BlossomFall />
        <div className="max-w-4xl mx-auto relative z-10 flex flex-col items-center">
            <header className="mb-8 w-full flex justify-between items-center animate-fade-in">
                <div className="text-left">
                    <h1 className="text-4xl md:text-6xl font-black text-transparent bg-clip-text bg-gradient-to-r from-amber-400 via-yellow-200 to-amber-500 py-2 uppercase tracking-tighter font-inter">
                        IELTS Examiner 2026
                    </h1>
                </div>
                {appState !== AppState.AUTH && (
                    <button 
                        onClick={() => setShowVocabBank(true)}
                        className="bg-amber-400 text-red-900 px-4 py-2 rounded-full font-bold shadow-lg hover:scale-105 transition-transform font-inter"
                    >
                        📚 Sổ Tay ({savedVocab.length})
                    </button>
                )}
            </header>

            <main className="w-full">
                {appState === AppState.AUTH ? (
                    <div className="flex justify-center items-center h-96">
                        <div className="api-key-card animate-fade-in text-center">
                            <h2 className="text-4xl font-black text-red-700 mb-6 font-inter">Start Practicing</h2>
                            <input 
                                type="text" 
                                value={apiKey} 
                                onChange={(e) => setApiKey(e.target.value)} 
                                placeholder="Nhập Gemini API Key..." 
                                className="w-full border-2 border-amber-100 p-4 rounded-xl mb-4 text-gray-800 text-lg focus:ring-4 focus:ring-amber-200 focus:outline-none transition-all font-inter"
                            />
                            <button 
                                onClick={() => { localStorage.setItem('user_api_key', apiKey); setAppState(AppState.HOME); }}
                                className="w-full bg-tet-gold py-4 rounded-xl font-black text-xl hover:brightness-110 transition-all shadow-lg active:scale-95 font-inter"
                            >ENTER</button>
                            <a href="https://aistudio.google.com/app/apikey" target="_blank" className="block mt-6 text-red-600 underline font-semibold text-lg hover:text-red-700 font-inter">Get a free API Key</a>
                        </div>
                    </div>
                ) : appState === AppState.HOME ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-fade-in">
                        <button onClick={() => handleModeSelect(TestMode.PART1)} className="tet-card p-10 hover:border-amber-400 transition-all text-left">
                            <span className="text-4xl block mb-2">🧧</span>
                            <h3 className="text-2xl font-bold text-amber-300">Part 1</h3>
                            <p className="text-amber-100/60">Làm quen và hỏi đáp ngắn</p>
                        </button>
                        <button onClick={() => handleModeSelect(TestMode.PART2)} className="tet-card p-10 hover:border-amber-400 transition-all text-left">
                            <span className="text-4xl block mb-2">🐎</span>
                            <h3 className="text-2xl font-bold text-amber-300">Part 2</h3>
                            <p className="text-amber-100/60">Cue Card - Nói liên tục 2 phút</p>
                        </button>
                        <button onClick={() => handleModeSelect(TestMode.PART3)} className="tet-card p-10 hover:border-amber-400 transition-all text-left">
                            <span className="text-4xl block mb-2">🏮</span>
                            <h3 className="text-2xl font-bold text-amber-300">Part 3</h3>
                            <p className="text-amber-100/60">Thảo luận chuyên sâu</p>
                        </button>
                        <button onClick={() => handleModeSelect(TestMode.FULL)} className="tet-card p-10 bg-amber-500/10 border-amber-400 border-2 scale-105 text-left">
                            <span className="text-4xl block mb-2">🏆</span>
                            <h3 className="text-2xl font-bold text-amber-400">Full Mock Test</h3>
                            <p className="text-amber-100/80">Trải nghiệm bài thi thực tế</p>
                        </button>
                    </div>
                ) : appState === AppState.PREPARATION ? (
                    <div className="text-center animate-fade-in">
                        <h2 className="text-3xl font-bold text-amber-400 mb-6 font-inter">Preparation Time (1 minute)</h2>
                        <div className="tet-card p-8 mb-8 text-left">
                            <h3 className="text-2xl font-bold text-amber-300 mb-4">{cueCard?.title}</h3>
                            <ul className="space-y-2 text-xl italic">{cueCard?.points.map((p, i) => <li key={i}>- {p}</li>)}</ul>
                        </div>
                        <Timer duration={60} onFinish={() => setAppState(AppState.SPEAKING)} />
                        <button onClick={() => setAppState(AppState.SPEAKING)} className="mt-8 bg-tet-gold px-12 py-4 rounded-full font-bold font-inter">Start Speaking</button>
                    </div>
                ) : appState === AppState.SPEAKING ? (
                    <div className="text-center py-10 animate-fade-in">
                        <div className="tet-card p-12 mb-10 max-w-2xl mx-auto">
                            <h2 className="text-4xl font-bold text-amber-200 mb-6 leading-relaxed italic">
                                "{renderText(currentStage === 'p2' ? cueCard?.title : questions[questionIndex])}"
                            </h2>
                            {isReading && <p className="text-amber-400 animate-pulse font-inter">Examiner is speaking...</p>}
                        </div>

                        <div className="flex flex-col items-center">
                            <button 
                                onMouseDown={startRecording} onMouseUp={stopRecording}
                                onTouchStart={startRecording} onTouchEnd={stopRecording}
                                className={`w-32 h-32 rounded-full flex items-center justify-center transition-all ${isRecording ? 'bg-red-500 pulse-ring' : 'bg-tet-gold shadow-2xl hover:scale-105 active:scale-95'}`}
                            >
                                <span className="text-4xl">{isRecording ? '🛑' : '🎤'}</span>
                            </button>
                            <p className="mt-4 font-bold text-amber-200 font-inter">{isRecording ? 'Nhả để gửi câu trả lời' : 'Nhấn và giữ để ghi âm'}</p>
                        </div>
                    </div>
                ) : appState === AppState.TRANSITION || appState === AppState.EVALUATING ? (
                    <div className="text-center p-20">
                        <div className="w-20 h-20 border-4 border-amber-500 border-t-transparent rounded-full animate-spin mb-8 mx-auto"></div>
                        <p className="text-3xl font-serif">{loadingMsg}</p>
                    </div>
                ) : appState === AppState.FEEDBACK ? (
                    <div className="w-full animate-fade-in">
                        <div className="flex flex-col md:flex-row gap-8">
                            <div className="md:w-1/3 flex flex-col gap-6">
                                <div className="tet-card p-10 text-center">
                                    <h3 className="text-2xl font-bold text-amber-300 mb-4 font-inter">Overall Band</h3>
                                    <div className="text-9xl font-black text-amber-400 font-inter">{renderText(evaluation?.overallScore)}</div>
                                </div>
                                <button onClick={() => setAppState(AppState.HOME)} className="bg-tet-gold py-6 rounded-xl font-bold text-xl font-inter">Luyện Tập Tiếp</button>
                            </div>
                            <div className="md:w-2/3 tet-card p-10 max-h-[80vh] overflow-y-auto custom-scrollbar text-left font-serif">
                                <h2 className="text-3xl font-bold text-amber-300 mb-8 border-b pb-4 font-inter">Kết Quả Chi Tiết</h2>

                                {sampleAnswer && (
                                    <div className="mb-12 p-8 bg-amber-50 text-red-950 rounded-2xl border-4 border-amber-300 shadow-xl">
                                        <h3 className="text-2xl font-black mb-4 font-inter uppercase">Band 8.5+ Sample Answer</h3>
                                        <div className="text-lg leading-relaxed mb-6 font-serif">
                                            {renderSampleWithHighlights(sampleAnswer.sampleText)}
                                        </div>
                                        <div className="bg-amber-100 p-4 rounded-lg italic text-sm font-inter">
                                            💡 Mẹo: Nhấp vào các từ in đậm để lưu vào sổ tay từ vựng của bạn.
                                        </div>
                                    </div>
                                )}

                                {['fluencyAndCoherence', 'lexicalResource', 'grammaticalRangeAndAccuracy', 'pronunciation'].map(k => (
                                    <div key={k} className="mb-8 p-6 bg-red-950/60 rounded-xl border border-amber-900/50">
                                        <div className="flex justify-between items-center mb-4">
                                            <h4 className="text-2xl font-bold text-amber-200 capitalize font-inter">{k.replace(/([A-Z])/g, ' $1')}</h4>
                                            <span className="bg-amber-500 text-red-950 px-4 py-1 rounded-full font-bold font-inter">Band {renderText(evaluation?.[k]?.score)}</span>
                                        </div>
                                        <div className="grid md:grid-cols-1 gap-4">
                                            <div>
                                                <p className="text-green-400 font-bold mb-1 font-inter">Ưu điểm:</p>
                                                <p className="text-amber-50/90 leading-relaxed mb-4">{renderText(evaluation?.[k]?.feedback?.strengths)}</p>
                                            </div>
                                            <div>
                                                <p className="text-orange-400 font-bold mb-1 font-inter">Cần cải thiện:</p>
                                                <p className="text-amber-50/90 leading-relaxed">{renderText(evaluation?.[k]?.feedback?.areasForImprovement)}</p>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                ) : null}
            </main>

            {showVocabBank && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
                    <div className="tet-card w-full max-w-2xl max-h-[80vh] overflow-hidden flex flex-col p-8">
                        <div className="flex justify-between items-center mb-6">
                            <h2 className="text-3xl font-bold text-amber-300 font-inter">Sổ Tay Từ Vựng</h2>
                            <button onClick={() => setShowVocabBank(false)} className="text-amber-200 text-4xl leading-none">&times;</button>
                        </div>
                        <div className="flex-1 overflow-y-auto custom-scrollbar space-y-4 pr-2">
                            {savedVocab.length === 0 ? (
                                <p className="text-center text-amber-100/50 italic py-10 text-xl font-inter">Chưa có từ vựng nào được lưu.</p>
                            ) : (
                                savedVocab.map((v, i) => (
                                    <div key={i} className="bg-amber-100/10 p-4 rounded-lg border border-amber-900 flex justify-between group">
                                        <div>
                                            <p className="text-xl font-bold text-amber-300 font-inter">{renderText(v.term)}</p>
                                            <p className="text-amber-50/80 italic">{renderText(v.definition)}</p>
                                        </div>
                                        <div className="text-right flex flex-col justify-between">
                                            <span className="text-xs opacity-40 font-inter">{renderText(v.date)}</span>
                                            <button 
                                                onClick={() => {
                                                    const updated = savedVocab.filter((_, idx) => idx !== i);
                                                    setSavedVocab(updated);
                                                    localStorage.setItem('saved_vocab', JSON.stringify(updated));
                                                }}
                                                className="text-red-400 opacity-0 group-hover:opacity-100 transition-opacity font-inter"
                                            >Xóa</button>
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>
                        <button onClick={() => setShowVocabBank(false)} className="mt-8 bg-tet-gold py-4 rounded-xl font-bold font-inter">Đóng</button>
                    </div>
                </div>
            )}
        </div>
    </div>
  );
};

const Timer = ({ duration, onFinish }) => {
  const [timeLeft, setTimeLeft] = useState(duration);
  useEffect(() => {
    if (timeLeft === 0) { onFinish(); return; }
    const interval = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    return () => clearInterval(interval);
  }, [timeLeft]);
  const m = String(Math.floor(timeLeft / 60)).padStart(2, '0');
  const s = String(timeLeft % 60).padStart(2, '0');
  return <div className="text-8xl font-black text-amber-400 font-mono">{m}:{s}</div>;
};

