import React, { useState, useEffect, useRef } from 'react';
import ReactDOM from 'react-dom/client';

// --- Constants & Types ---
const APP_STATE = {
  HOME: 'home',
  SETUP: 'setup',
  SPEAKING: 'speaking',
  PREP: 'prep',
  EVALUATING: 'evaluating',
  FEEDBACK: 'feedback'
};

const PARTS = {
  P1: { id: 1, name: 'Part 1: General', icon: '🧧', desc: 'Hỏi đáp về các chủ đề quen thuộc' },
  P2: { id: 2, name: 'Part 2: Long Turn', icon: '🐎', desc: 'Nói về một chủ đề trong 2 phút' },
  P3: { id: 3, name: 'Part 3: Discussion', icon: '🏮', desc: 'Thảo luận sâu về chủ đề Part 2' }
};

// --- Components ---

const Blossom = () => {
  const [petals, setPetals] = useState([]);
  useEffect(() => {
    const p = Array.from({ length: 25 }).map((_, i) => ({
      id: i,
      left: Math.random() * 100 + 'vw',
      delay: Math.random() * 10 + 's',
      duration: Math.random() * 5 + 5 + 's',
      size: Math.random() * 10 + 10 + 'px'
    }));
    setPetals(p);
  }, []);

  return (
    <>
      {petals.map(p => (
        <div
          key={p.id}
          className="blossom"
