const App = () => {
  const [state, setState] = useState(APP_STATE.HOME);
  const [selectedPart, setSelectedPart] = useState(null);
  const [questionIndex, setQuestionIndex] = useState(0);
  const [questions, setQuestions] = useState([]);
  const [cueCard, setCueCard] = useState(null);
  const [sessionData, setSessionData] = useState([]);
  const [isRecording, setIsRecording] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [evaluation, setEvaluation] = useState(null);
  const [sample, setSample] = useState(null);
  const [savedVocab, setSavedVocab] = useState(JSON.parse(localStorage.getItem('ielts_vocab') || '[]'));
  const [prepTime, setPrepTime] = useState(60);

  const mediaRecorderRef = useRef(null);
  const chunksRef = useRef([]);
  const audioRef = useRef(null);

  // --- API Handlers ---

  const callApi = async (type, payload) => {
    const res = await fetch('/api/gemini', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ type, payload })
    });
    return res.json();
  };

  const startPractice = async (part) => {
    setSelectedPart(part);
    setIsProcessing(true);
    try {
      const data = await callApi('getQuestions', { partId: part.id });
      if (part.id === 2) {
        setCueCard(data.cueCard);
        setState(APP_STATE.PREP);
      } else {
        setQuestions(data.questions);
        setQuestionIndex(0);
        setState(APP_STATE.SPEAKING);
      }
    } catch (e) {
      alert("Lỗi khởi tạo bài tập. Vui lòng thử lại.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSpeech = async (text) => {
    setIsSpeaking(true);
    const data = await callApi('tts', { text });
    if (data.audio) {
      const audio = new Audio(`data:audio/wav;base64,${data.audio}`);
      audio.onended = () => setIsSpeaking(false);
      audio.play();
      audioRef.current = audio;
    } else {
      setIsSpeaking(false);
    }
  };

  useEffect(() => {
    if (state === APP_STATE.SPEAKING && selectedPart) {
      const q = selectedPart.id === 2 ? "Now, please start your talk." : questions[questionIndex];
      if (q) handleSpeech(q);
    }
  }, [state, questionIndex]);

  const toggleRecording = async () => {
    if (isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsProcessing(true);
    } else {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      chunksRef.current = [];
      recorder.ondataavailable = e => chunksRef.current.push(e.data);
      recorder.onstop = async () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(blob);
        reader.onloadend = async () => {
          const base64 = reader.result.split(',')[1];
          const result = await callApi('transcribe', { audio: base64 });
          const transcript = result.transcription || "[Không nghe rõ]";

          const newEntry = { 
            question: selectedPart.id === 2 ? cueCard.title : questions[questionIndex], 
            answer: transcript 
          };
          const updatedSession = [...sessionData, newEntry];
          setSessionData(updatedSession);

          if (selectedPart.id === 2 || questionIndex >= questions.length - 1) {
            finishSession(updatedSession);
          } else {
            setQuestionIndex(prev => prev + 1);
            setIsProcessing(false);
          }
        };
      };
      recorder.start();
      mediaRecorderRef.current = recorder;
      setIsRecording(true);
    }
  };

  const finishSession = async (finalData) => {
    setState(APP_STATE.EVALUATING);
    const evalData = await callApi('evaluate', { 
      data: finalData, 
      partId: selectedPart.id,
      topic: selectedPart.id === 2 ? cueCard.title : "General"
    });
    setEvaluation(evalData);

    if (selectedPart.id === 2) {
      const sampleData = await callApi('getSample', { topic: cueCard.title, points: cueCard.points });
      setSample(sampleData);
    }
    setState(APP_STATE.FEEDBACK);
  };

  const saveVocab = (term, def) => {
    if (savedVocab.find(v => v.term === term)) return;
    const updated = [...savedVocab, { term, def }];
    setSavedVocab(updated);
    localStorage.setItem('ielts_vocab', JSON.stringify(updated));
  };

  // --- Prep Timer Logic ---
  useEffect(() => {
    let timer;
    if (state === APP_STATE.PREP && prepTime > 0) {
      timer = setInterval(() => setPrepTime(p => p - 1), 1000);
    } else if (prepTime === 0 && state === APP_STATE.PREP) {
      setState(APP_STATE.SPEAKING);
    }
    return () => clearInterval(timer);
  }, [state, prepTime]);

  // --- Render Functions ---

  const renderSample = (text) => {
    const parts = text.split(/(\[\[.*?\]\])/g);
    return parts.map((part, i) => {
      if (part.startsWith('[[') && part.endsWith(']]')) {
        const [term, def] = part.slice(2, -2).split('|');
        return (
          <span 
