            onClick={() => saveVocab(term, def)}
            title={def}
          >
            {term}
          </span>
        );
      }
      return part;
    });
  };

  return (
    <div className="relative z-10 p-6 max-w-4xl mx-auto min-h-screen flex flex-col">
      <Blossom />

      <header className="text-center mb-10 mt-6">
        <h1 className="text-5xl md:text-7xl font-black text-transparent bg-clip-text bg-gradient-to-r from-yellow-200 via-amber-400 to-yellow-600 mb-2 py-4">
