        <p className="text-amber-200/80 italic text-xl">Năm Mới Bính Ngọ - Luyện Nói Cực Đỉnh</p>
      </header>

      <main className="flex-1 flex flex-col items-center">
        {state === APP_STATE.HOME && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full animate-fade-in">
            {Object.values(PARTS).map(part => (
              <button
                key={part.id}
                onClick={() => startPractice(part)}
                className="tet-card p-8 rounded-3xl hover:scale-105 transition-all text-left flex flex-col items-start group"
              >
                <span className="text-5xl mb-4 group-hover:scale-110 transition-transform">{part.icon}</span>
                <h3 className="text-2xl font-bold text-amber-300 mb-2">{part.name}</h3>
                <p className="text-amber-50/70">{part.desc}</p>
              </button>
            ))}
          </div>
        )}

        {isProcessing && (
          <div className="fixed inset-0 bg-red-950/80 backdrop-blur-md flex flex-col items-center justify-center z-50">
            <div className="w-16 h-16 border-4 border-amber-400 border-t-transparent rounded-full animate-spin mb-4"></div>
            <p className="text-amber-200 text-xl font-bold">Đang xử lý dữ liệu Tet...</p>
          </div>
