            <div className="text-left bg-red-900/40 p-6 rounded-2xl border border-amber-900/50 mb-8">
              <h3 className="text-2xl font-bold text-amber-300 mb-4">{cueCard.title}</h3>
              <ul className="space-y-2 italic text-lg opacity-90">
                {cueCard.points.map((p, i) => <li key={i}>- {p}</li>)}
