import { GoogleGenAI, Type, Modality } from "@google/genai";

const evaluationSchema = {
  type: Type.OBJECT,
  properties: {
    fluencyAndCoherence: { type: Type.OBJECT, properties: { score: { type: Type.NUMBER }, feedback: { type: Type.OBJECT, properties: { strengths: { type: Type.STRING }, areasForImprovement: { type: Type.STRING } } } } },
    lexicalResource: { type: Type.OBJECT, properties: { score: { type: Type.NUMBER }, feedback: { type: Type.OBJECT, properties: { strengths: { type: Type.STRING }, areasForImprovement: { type: Type.STRING } } } } },
    grammaticalRangeAndAccuracy: { type: Type.OBJECT, properties: { score: { type: Type.NUMBER }, feedback: { type: Type.OBJECT, properties: { strengths: { type: Type.STRING }, areasForImprovement: { type: Type.STRING } } } } },
    pronunciation: { type: Type.OBJECT, properties: { score: { type: Type.NUMBER }, feedback: { type: Type.OBJECT, properties: { strengths: { type: Type.STRING }, areasForImprovement: { type: Type.STRING } } } } },
    overallScore: { type: Type.NUMBER }
  },
  required: ["fluencyAndCoherence", "lexicalResource", "grammaticalRangeAndAccuracy", "pronunciation", "overallScore"]
};

const questionsSchema = {
  type: Type.OBJECT,
  properties: {
    questions: { type: Type.ARRAY, items: { type: Type.STRING } },
    cueCard: { type: Type.OBJECT, properties: { title: { type: Type.STRING }, points: { type: Type.ARRAY, items: { type: Type.STRING } } } }
  }
};

const sampleSchema = {
  type: Type.OBJECT,
  properties: {
    sampleText: { type: Type.STRING, description: "A high-scoring sample answer with [[term|vietnamese_definition]] tags." }
  },
  required: ["sampleText"]
};

export default async function handler(req, res) {
  const { type, payload } = req.body;
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    if (type === 'getQuestions') {
      const prompt = payload.partId === 2 
        ? "Generate an IELTS Speaking Part 2 cue card related to Lunar New Year or common life themes."
        : `Generate 3 IELTS Speaking Part ${payload.partId} questions about general life or festivals.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json", responseSchema: questionsSchema }
      });
      return res.status(200).json(JSON.parse(response.text));
    }

    if (type === 'transcribe') {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [{ inlineData: { mimeType: 'audio/webm', data: payload.audio } }, { text: "Transcribe this audio response for an IELTS speaking test. Keep fillers like 'um', 'ah' if audible." }] }
      });
      return res.status(200).json({ transcription: response.text });
    }

    if (type === 'evaluate') {
      const prompt = `Evaluate the following IELTS Speaking Part ${payload.partId} performance.
      Session data: ${JSON.stringify(payload.data)}
      Topic: ${payload.topic}

      Requirements:
      1. Use official IELTS band descriptors.
      2. Provide feedback in VIETNAMESE.
      3. Scores should be realistic (integers or .5).`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json", responseSchema: evaluationSchema }
      });
      return res.status(200).json(JSON.parse(response.text));
    }

    if (type === 'getSample') {
      const prompt = `Generate a Band 9 sample answer for this IELTS topic: "${payload.topic}". 
      Points included: ${payload.points?.join(', ')}.
      IMPORTANT: Wrap top-tier collocations/idioms in [[term|vietnamese_definition]] format. Example: [[once in a blue moon|hiếm khi xảy ra]].`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json", responseSchema: sampleSchema }
      });
      return res.status(200).json(JSON.parse(response.text));
    }

    if (type === 'tts') {
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-preview-tts',
        contents: { parts: [{ text: `Say this like a professional IELTS examiner with a clear accent: ${payload.text}` }] },
        config: { 
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Charon' } } }
        }
      });
      const base64 = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      return res.status(200).json({ audio: base64 });
    }

    return res.status(400).json({ error: "Invalid type" });
  } catch (e) {
    console.error(e);
    return res.status(500).json({ error: e.message });
  }
}

