  return (
    <>
      {petals.map(p => (
        <div
          key={p.id}
          className="blossom"
          style={{
            left: p.left,
            animationDelay: p.delay,
            animationDuration: p.duration,
            fontSize: p.size,
            color: '#fbbf24'
          }}
        >
          🌸
        </div>
      ))}
    </>
  );
};

